1	package workorders
2	
3	import (
4		"time"
5	
6		"gorm.io/gorm"
7	)
8	
9	// Repository handles all work order database operations.
10	type Repository struct {
11		db *gorm.DB
12	}
13	
14	// NewRepository creates a new work order Repository.
15	func NewRepository(db *gorm.DB) *Repository {
16		return &Repository{db: db}
17	}
18	
19	// Create inserts a new work order record.
20	func (r *Repository) Create(wo *WorkOrder) error {
21		return r.db.Create(wo).Error
22	}
23	
24	// FindByID loads a work order by its primary key.
25	func (r *Repository) FindByID(id uint64) (*WorkOrder, error) {
26		var wo WorkOrder
27		err := r.db.Where("id = ?", id).First(&wo).Error
28		if err != nil {
29			return nil, err
30		}
31		return &wo, nil
32	}
33	
34	// FindByUUID loads a work order by its UUID.
35	func (r *Repository) FindByUUID(uuid string) (*WorkOrder, error) {
36		var wo WorkOrder
37		err := r.db.Where("uuid = ?", uuid).First(&wo).Error
38		if err != nil {
39			return nil, err
40		}
41		return &wo, nil
42	}
43	
44	// Update saves changes to an existing work order.
45	func (r *Repository) Update(wo *WorkOrder) error {
46		return r.db.Save(wo).Error
47	}
48	
49	// ListFilters holds the optional filters for listing work orders.
50	type ListFilters struct {
51		PropertyID  *uint64
52		PropertyIDs []uint64 // for multi-property scoping (PM access control)
53		Status      string
54		AssignedTo  *uint64
55		TenantID    *uint64
56		Priority    string
57		DateFrom    *time.Time
58		DateTo      *time.Time
59	}
60	
61	// List retrieves work orders matching the given filters with pagination.
62	func (r *Repository) List(filters ListFilters, offset, limit int) ([]WorkOrder, int64, error) {
63		query := r.db.Model(&WorkOrder{})
64	
65		if filters.PropertyID != nil {
66			query = query.Where("property_id = ?", *filters.PropertyID)
67		} else if len(filters.PropertyIDs) > 0 {
68			query = query.Where("property_id IN ?", filters.PropertyIDs)
69		}
70		if filters.Status != "" {
71			query = query.Where("status = ?", filters.Status)
72		}
73		if filters.AssignedTo != nil {
74			query = query.Where("assigned_to = ?", *filters.AssignedTo)
75		}
76		if filters.TenantID != nil {
77			query = query.Where("tenant_id = ?", *filters.TenantID)
78		}
79		if filters.Priority != "" {
80			query = query.Where("priority = ?", filters.Priority)
81		}
82		if filters.DateFrom != nil {
83			query = query.Where("created_at >= ?", *filters.DateFrom)
84		}
85		if filters.DateTo != nil {
86			query = query.Where("created_at <= ?", *filters.DateTo)
87		}
88	
89		var total int64
90		if err := query.Count(&total).Error; err != nil {
91			return nil, 0, err
92		}
93	
94		var orders []WorkOrder
95		err := query.Order("created_at DESC").Offset(offset).Limit(limit).Find(&orders).Error
96		if err != nil {
97			return nil, 0, err
98		}
99	
100		return orders, total, nil
101	}
102	
103	// FindByTenant retrieves all work orders for a specific tenant with pagination.
104	func (r *Repository) FindByTenant(tenantID uint64, offset, limit int) ([]WorkOrder, int64, error) {
105		return r.List(ListFilters{TenantID: &tenantID}, offset, limit)
106	}
107	
108	// FindByTechnician retrieves all work orders assigned to a specific technician with pagination.
109	func (r *Repository) FindByTechnician(technicianID uint64, offset, limit int) ([]WorkOrder, int64, error) {
110		return r.List(ListFilters{AssignedTo: &technicianID}, offset, limit)
111	}
