113	// FindOverdueSLA retrieves work orders that have breached their SLA but are not yet completed or archived.
114	func (r *Repository) FindOverdueSLA() ([]WorkOrder, error) {
115		var orders []WorkOrder
116		err := r.db.Where("sla_due_at IS NOT NULL AND sla_due_at <= ? AND sla_breached_at IS NULL AND status NOT IN (?, ?)",
117			time.Now().UTC(), "Completed", "Archived").
118			Find(&orders).Error
119		return orders, err
120	}
121	
122	// CreateEvent inserts a new work order event (append-only).
123	func (r *Repository) CreateEvent(event *WorkOrderEvent) error {
124		return r.db.Create(event).Error
125	}
126	
127	// ListEvents retrieves all events for a work order, ordered by creation time.
128	func (r *Repository) ListEvents(workOrderID uint64) ([]WorkOrderEvent, error) {
129		var events []WorkOrderEvent
130		err := r.db.Where("work_order_id = ?", workOrderID).
131			Order("created_at ASC").
132			Find(&events).Error
133		return events, err
134	}
