160	// FindWorkOrderForAttachment returns the ID and UUID of a work order for use by the attachment service.
161	// This method satisfies the attachments.WorkOrderQuerier interface.
162	func (r *Repository) FindWorkOrderForAttachment(id uint64) (uint64, string, error) {
163		wo, err := r.FindByID(id)
164		if err != nil {
165			return 0, "", err
166		}
167		return wo.ID, wo.UUID, nil
168	}
169	
170	// IsManagedBy checks whether userID is an active staff member on the given property.
171	// Queries the property_staff_assignments table directly.
172	func (r *Repository) IsManagedBy(propertyID, userID uint64) (bool, error) {
173		var count int64
174		err := r.db.Table("property_staff_assignments").
175			Where("property_id = ? AND user_id = ? AND is_active = ?", propertyID, userID, true).
176			Count(&count).Error
177		return count > 0, err
178	}
179	
180	// GetManagedPropertyIDs returns all property IDs the user is actively assigned to.
181	func (r *Repository) GetManagedPropertyIDs(userID uint64) ([]uint64, error) {
182		var ids []uint64
183		err := r.db.Table("property_staff_assignments").
184			Where("user_id = ? AND is_active = ?", userID, true).
185			Pluck("property_id", &ids).Error
186		return ids, err
187	}
188	
189	// GetWorkOrderOwnerID returns the TenantID (original creator) of the given work order.
190	// This method satisfies the attachments.WorkOrderQuerier interface for ownership checks.
191	func (r *Repository) GetWorkOrderOwnerID(woID uint64) (uint64, error) {
192		var wo WorkOrder
193		if err := r.db.Select("tenant_id").Where("id = ?", woID).First(&wo).Error; err != nil {
194			return 0, err
195		}
196		return wo.TenantID, nil
197	}
