21	// Create handles POST /work-orders
22	func (h *Handler) Create(c *gin.Context) {
23		var req CreateWorkOrderRequest
24		if err := c.ShouldBindJSON(&req); err != nil {
25			common.RespondError(c, common.NewBadRequestError("invalid request body"))
26			return
27		}
28	
29		userID := c.GetUint64(string(common.CtxKeyUserID))
30		roles := c.GetStringSlice(string(common.CtxKeyRoles))
31		ip := c.ClientIP()
32		requestID, _ := c.Get(string(common.CtxKeyRequestID))
33		reqID, _ := requestID.(string)
34	
35		// Only tenants can create work orders.
36		if !hasRole(roles, common.RoleTenant) {
37			common.RespondError(c, common.NewForbiddenError("only tenants can create work orders"))
38			return
39		}
40	
41		wo, appErr := h.service.Create(req, userID, ip, reqID)
42		if appErr != nil {
43			common.RespondError(c, appErr)
44			return
45		}
46	
47		common.Created(c, ToWorkOrderResponse(wo))
48	}
