73	// List handles GET /work-orders
74	func (h *Handler) List(c *gin.Context) {
75		userID := c.GetUint64(string(common.CtxKeyUserID))
76		roles := c.GetStringSlice(string(common.CtxKeyRoles))
77	
78		var req WorkOrderListRequest
79		if err := c.ShouldBindQuery(&req); err != nil {
80			common.RespondError(c, common.NewBadRequestError("invalid query parameters"))
81			return
82		}
83	
84		if req.Page == 0 {
85			req.Page = 1
86		}
87		if req.PerPage == 0 {
88			req.PerPage = 20
89		}
90	
91		// Scope based on role.
92		if hasRole(roles, common.RoleTenant) && !hasRole(roles, common.RolePropertyManager) && !hasRole(roles, common.RoleSystemAdmin) {
93			// Push the tenant filter to the repository so total and results are both scoped.
94			tenantID := userID
95			req.TenantID = &tenantID
96			req.PropertyID = nil
97			req.AssignedTo = nil
98		}
99	
100		if hasRole(roles, common.RoleTechnician) && !hasRole(roles, common.RolePropertyManager) && !hasRole(roles, common.RoleSystemAdmin) {
101			// Technicians see only their assigned work orders.
102			assignedTo := userID
103			req.AssignedTo = &assignedTo
104		}
105	
106		// PropertyManagers see only work orders for properties they manage.
107		if hasRole(roles, common.RolePropertyManager) && !hasRole(roles, common.RoleSystemAdmin) && req.PropertyID == nil {
108			managedIDs, err := h.service.GetManagedPropertyIDs(userID)
109			if err != nil {
110				common.RespondError(c, common.NewInternalError("failed to resolve managed properties"))
111				return
112			}
113			req.PropertyIDs = managedIDs
114		}
115	
116		orders, total, appErr := h.service.List(req)
117		if appErr != nil {
118			common.RespondError(c, appErr)
119			return
120		}
121	
122		responses := make([]WorkOrderResponse, len(orders))
123		for i := range orders {
124			responses[i] = ToWorkOrderResponse(&orders[i])
125		}
126	
127		meta := common.BuildMeta(req.Page, req.PerPage, total)
128		common.SuccessWithMeta(c, responses, meta)
129	}
