132	func (h *Handler) Transition(c *gin.Context) {
133		woID, err := parseIDParam(c, "id")
134		if err != nil {
135			common.RespondError(c, common.NewBadRequestError("invalid work order ID"))
136			return
137		}
138	
139		var req TransitionRequest
140		if err := c.ShouldBindJSON(&req); err != nil {
141			common.RespondError(c, common.NewBadRequestError("invalid request body"))
142			return
143		}
144	
145		userID := c.GetUint64(string(common.CtxKeyUserID))
146		roles := c.GetStringSlice(string(common.CtxKeyRoles))
147		ip := c.ClientIP()
148		requestID, _ := c.Get(string(common.CtxKeyRequestID))
149		reqID, _ := requestID.(string)
150	
151		// Check authorization for the transition.
