172	// Reassign handles POST /work-orders/:id/reassign
173	func (h *Handler) Reassign(c *gin.Context) {
174		woID, err := parseIDParam(c, "id")
175		if err != nil {
176			common.RespondError(c, common.NewBadRequestError("invalid work order ID"))
177			return
178		}
179	
180		var req ReassignRequest
181		if err := c.ShouldBindJSON(&req); err != nil {
182			common.RespondError(c, common.NewBadRequestError("invalid request body"))
183			return
184		}
185	
186		userID := c.GetUint64(string(common.CtxKeyUserID))
187		roles := c.GetStringSlice(string(common.CtxKeyRoles))
188		ip := c.ClientIP()
189		requestID, _ := c.Get(string(common.CtxKeyRequestID))
190		reqID, _ := requestID.(string)
191	
192		// Only PropertyManagers or SystemAdmins can reassign.
193		if !hasRole(roles, common.RolePropertyManager) && !hasRole(roles, common.RoleSystemAdmin) {
194			common.RespondError(c, common.NewForbiddenError("only property managers can reassign work orders"))
195			return
196		}
197	
198		// PM must manage the work order's property.
199		if hasRole(roles, common.RolePropertyManager) && !hasRole(roles, common.RoleSystemAdmin) {
200			existing, appErr := h.service.GetByID(woID)
201			if appErr != nil {
202				common.RespondError(c, appErr)
203				return
204			}
205			managed, err := h.service.IsManagedBy(existing.PropertyID, userID)
206			if err != nil || !managed {
207				common.RespondError(c, common.NewForbiddenError("you do not manage the property for this work order"))
208				return
209			}
210		}
211	
212		wo, appErr := h.service.Reassign(woID, req, userID, ip, reqID)
213		if appErr != nil {
214			common.RespondError(c, appErr)
215			return
216		}
217	
218		common.Success(c, ToWorkOrderResponse(wo))
219	}
