69	// Create validates the input and creates a new work order.
70	// It calculates the SLA deadline based on priority and attempts auto-dispatch.
71	func (s *Service) Create(req CreateWorkOrderRequest, tenantID uint64, ip, requestID string) (*WorkOrder, *common.AppError) {
72		// Validate required fields.
73		var fieldErrors []*common.FieldError
74	
75		if fe := common.ValidateDescription(req.Description); fe != nil {
76			fieldErrors = append(fieldErrors, fe)
77		}
78		if fe := common.ValidatePriority(req.Priority); fe != nil {
79			fieldErrors = append(fieldErrors, fe)
80		}
81	
82		// Validate optional date/time fields.
83		var preferredDate *time.Time
84		if req.PreferredAccessDate != "" {
85			if fe := common.ValidateDateFormat("preferred_access_date", req.PreferredAccessDate); fe != nil {
86				fieldErrors = append(fieldErrors, fe)
87			} else {
88				parsed, err := common.ParseDateMMDDYYYY(req.PreferredAccessDate)
89				if err != nil {
90					fieldErrors = append(fieldErrors, &common.FieldError{Field: "preferred_access_date", Message: "invalid date"})
91				} else {
92					preferredDate = &parsed
93				}
94			}
95		}
96		if req.PreferredAccessStartTime != "" {
97			if fe := common.ValidateTimeFormat("preferred_access_start_time", req.PreferredAccessStartTime); fe != nil {
98				fieldErrors = append(fieldErrors, fe)
99			}
100		}
101		if req.PreferredAccessEndTime != "" {
102			if fe := common.ValidateTimeFormat("preferred_access_end_time", req.PreferredAccessEndTime); fe != nil {
103				fieldErrors = append(fieldErrors, fe)
104			}
105		}
106	
107		if appErr := common.CollectFieldErrors(fieldErrors...); appErr != nil {
108			return nil, appErr
109		}
110	
111		now := time.Now().UTC()
112		slaDue := CalculateSLA(req.Priority, now)
113	
114		wo := &WorkOrder{
115			UUID:                     uuid.New().String(),
116			PropertyID:               req.PropertyID,
117			UnitID:                   req.UnitID,
118			TenantID:                 tenantID,
119			Description:              req.Description,
120			Priority:                 req.Priority,
121			Status:                   common.WOStatusNew,
122			IssueType:                req.IssueType,
123			SkillTag:                 req.SkillTag,
124			Tags:                     datatypes.JSON(req.Tags),
125			PreferredAccessDate:      preferredDate,
126			PreferredAccessStartTime: req.PreferredAccessStartTime,
127			PreferredAccessEndTime:   req.PreferredAccessEndTime,
128			SLADueAt:                 &slaDue,
129		}
130	
131		if err := s.repo.Create(wo); err != nil {
132			return nil, common.NewInternalError("failed to create work order")
133		}
134	
135		// Create the initial event.
136		s.createEvent(wo.ID, &tenantID, "created", "", common.WOStatusNew, "Work order created", nil)
137	
138		// Attempt auto-dispatch if skill tag is provided.
139		if req.SkillTag != "" {
140			result, err := s.dispatch.Dispatch(req.PropertyID, req.SkillTag)
141			if err == nil && result.Assigned {
142				wo.AssignedTo = &result.TechnicianID
143				wo.Status = common.WOStatusAssigned
144				if err := s.repo.Update(wo); err == nil {
145					s.createEvent(wo.ID, &tenantID, "auto_dispatched", common.WOStatusNew, common.WOStatusAssigned,
146						fmt.Sprintf("Auto-dispatched to technician %d", result.TechnicianID), nil)
147					// Notify the assigned technician.
148					if s.notifier != nil {
149						_ = s.notifier.SendEvent("work_order_assigned", result.TechnicianID, map[string]string{
150							"work_order_id": fmt.Sprintf("%d", wo.ID),
151							"priority":      wo.Priority,
152						})
153					}
154				}
155			} else if err == nil && !result.Assigned {
156				s.createEvent(wo.ID, &tenantID, "dispatch_failed", "", "", result.Message, nil)
157			}
158		}
159	
160		// Audit log.
161		s.audit.Log(tenantID, common.AuditActionCreate, "WorkOrder", wo.ID, "Work order created", ip, requestID)
162	
163		return wo, nil
164	}
