243	// Transition validates and applies a status transition on a work order.
244	func (s *Service) Transition(woID uint64, req TransitionRequest, actorID uint64, ip, requestID string) (*WorkOrder, *common.AppError) {
245		wo, appErr := s.GetByID(woID)
246		if appErr != nil {
247			return nil, appErr
248		}
249	
250		if !IsValidTransition(wo.Status, req.ToStatus) {
251			return nil, common.NewValidationError(
252				fmt.Sprintf("invalid transition from %s to %s", wo.Status, req.ToStatus),
253			)
254		}
255	
256		fromStatus := wo.Status
257		wo.Status = req.ToStatus
258		now := time.Now().UTC()
259	
260		// Set timestamps for terminal states.
261		if req.ToStatus == common.WOStatusCompleted {
262			wo.CompletedAt = &now
263		}
264		if req.ToStatus == common.WOStatusArchived {
265			wo.ArchivedAt = &now
266		}
267	
268		if err := s.repo.Update(wo); err != nil {
269			return nil, common.NewInternalError("failed to update work order status")
270		}
271	
272		description := fmt.Sprintf("Status changed from %s to %s", fromStatus, req.ToStatus)
273		if req.Notes != "" {
274			description += ": " + req.Notes
275		}
276		s.createEvent(wo.ID, &actorID, "status_change", fromStatus, req.ToStatus, description, nil)
277	
278		s.audit.Log(actorID, common.AuditActionStatusChange, "WorkOrder", wo.ID, description, ip, requestID)
279	
280		return wo, nil
281	}
