387	// Rate allows a tenant to rate a completed work order.
388	func (s *Service) Rate(woID uint64, req RateWorkOrderRequest, tenantID uint64, ip, requestID string) (*WorkOrder, *common.AppError) {
389		// Validate rating.
390		var fieldErrors []*common.FieldError
391		if fe := common.ValidateRating(req.Rating); fe != nil {
392			fieldErrors = append(fieldErrors, fe)
393		}
394		if req.Feedback != "" {
395			if fe := common.ValidateFeedback(req.Feedback); fe != nil {
396				fieldErrors = append(fieldErrors, fe)
397			}
398		}
399		if appErr := common.CollectFieldErrors(fieldErrors...); appErr != nil {
400			return nil, appErr
401		}
402	
403		wo, appErr := s.GetByID(woID)
404		if appErr != nil {
405			return nil, appErr
406		}
407	
408		// Only the tenant who created the work order can rate it.
409		if wo.TenantID != tenantID {
410			return nil, common.NewForbiddenError("only the work order tenant can rate it")
411		}
412	
413		// Only completed work orders can be rated.
414		if wo.Status != common.WOStatusCompleted {
415			return nil, common.NewValidationError("only completed work orders can be rated")
416		}
417	
418		// Prevent re-rating.
419		if wo.Rating != nil {
420			return nil, common.NewConflictError("work order has already been rated")
421		}
422	
423		rating := uint8(req.Rating)
424		wo.Rating = &rating
425		if req.Feedback != "" {
426			wo.Feedback = &req.Feedback
427		}
428	
429		if err := s.repo.Update(wo); err != nil {
430			return nil, common.NewInternalError("failed to rate work order")
431		}
432	
433		s.createEvent(wo.ID, &tenantID, "rated", "", "",
434			fmt.Sprintf("Rated %d/5", req.Rating), nil)
435	
436		s.audit.Log(tenantID, common.AuditActionUpdate, "WorkOrder", wo.ID,
437			fmt.Sprintf("Work order rated %d/5", req.Rating), ip, requestID)
438	
439		return wo, nil
440	}
