28	// canAccessWorkOrder returns true if the actor (identified by actorID and roles)
29	// is allowed to access attachments for the given work order.
30	// A Tenant may only access attachments for work orders they created;
31	// all other roles have access.
32	func (s *Service) canAccessWorkOrder(woID, actorID uint64, roles []string) (bool, error) {
