87	// upload to work orders they created; all other roles may upload to any work order.
88	func (s *Service) Upload(workOrderID uint64, file *multipart.FileHeader, uploaderID uint64, uploaderRoles []string, ip, requestID string) (*Attachment, *common.AppError) {
89		// Object-level authorization: verify the uploader has access to this work order.
90		ok, err := s.canAccessWorkOrder(workOrderID, uploaderID, uploaderRoles)
91		if err != nil {
92			return nil, common.NewNotFoundError("Work order")
93		}
94		if !ok {
95			return nil, common.NewForbiddenError("you do not have access to this work order")
96		}
97	
98		// Validate file size.
99		if file.Size > MaxFileSize {
100			return nil, common.NewPayloadTooLargeError("file must be at most 5 MB")
101		}
102	
103		// Check attachment count limit.
104		currentCount, err := s.repo.CountByEntity(entityTypeWorkOrder, workOrderID)
105		if err != nil {
106			return nil, common.NewInternalError("failed to check attachment count")
107		}
108		if fe := common.ValidateAttachmentCount(currentCount, 1, MaxAttachmentsPerWorkOrder); fe != nil {
109			return nil, common.NewValidationError("Validation failed", *fe)
110		}
111	
112		// Look up the work order to get its UUID for the storage path.
113		_, woUUID, err := s.woQuerier.FindWorkOrderForAttachment(workOrderID)
114		if err != nil {
115			return nil, common.NewNotFoundError("Work order")
116		}
117	
118		// Open the uploaded file.
119		src, err := file.Open()
120		if err != nil {
121			return nil, common.NewInternalError("failed to open uploaded file")
122		}
123		defer src.Close()
124	
125		// Read the file header for magic byte validation.
126		header := make([]byte, 512)
127		n, err := src.Read(header)
128		if err != nil && err != io.EOF {
129			return nil, common.NewInternalError("failed to read file header")
130		}
131		header = header[:n]
132	
133		// Validate magic bytes.
134		detectedMIME, fe := common.ValidateFileSignature(header)
135		if fe != nil {
136			return nil, common.NewValidationError("Validation failed", *fe)
137		}
138	
139		// Validate declared MIME against detected.
140		declaredMIME := strings.ToLower(file.Header.Get("Content-Type"))
141		if fe := common.ValidateImageMIME(declaredMIME); fe != nil {
142			return nil, common.NewValidationError("Validation failed", *fe)
143		}
144		if declaredMIME != detectedMIME {
145			return nil, common.NewValidationError("declared MIME type does not match file content")
146		}
147	
148		// Reset reader to beginning for hashing and storage.
149		if _, err := src.Seek(0, io.SeekStart); err != nil {
150			return nil, common.NewInternalError("failed to reset file reader")
151		}
152	
153		// Compute SHA-256 hash.
154		hasher := sha256.New()
155		fileBytes, err := io.ReadAll(src)
156		if err != nil {
157			return nil, common.NewInternalError("failed to read file")
158		}
159		hasher.Write(fileBytes)
160		hash := hex.EncodeToString(hasher.Sum(nil))
161	
162		// Determine file extension from detected MIME.
163		ext := ".jpg"
164		if detectedMIME == "image/png" {
165			ext = ".png"
166		}
167	
168		// Generate storage path.
169		attachUUID := uuid.New().String()
170		storageDirRel := filepath.Join("attachments", woUUID)
171		storageDir := filepath.Join(s.storageRoot, storageDirRel)
172		if err := os.MkdirAll(storageDir, 0750); err != nil {
173			return nil, common.NewInternalError("failed to create storage directory")
174		}
175	
176		filename := attachUUID + ext
177		storagePath := filepath.Join(storageDirRel, filename)
178		fullPath := filepath.Join(s.storageRoot, storagePath)
179	
180		// Write file to disk.
181		if err := os.WriteFile(fullPath, fileBytes, 0640); err != nil {
182			return nil, common.NewInternalError("failed to write file to storage")
183		}
184	
185		// Create the database record.
186		attachment := &Attachment{
187			UUID:        attachUUID,
188			EntityType:  entityTypeWorkOrder,
189			EntityID:    workOrderID,
190			Filename:    file.Filename,
191			MimeType:    detectedMIME,
192			FileSize:    uint64(file.Size),
193			SHA256Hash:  hash,
194			StoragePath: storagePath,
195			UploadedBy:  uploaderID,
196		}
197	
198		if err := s.repo.Create(attachment); err != nil {
199			// Clean up the file on DB failure.
200			_ = os.Remove(fullPath)
201			return nil, common.NewInternalError("failed to save attachment record")
202		}
203	
204		s.audit.Log(uploaderID, common.AuditActionCreate, "Attachment", attachment.ID,
205			fmt.Sprintf("Uploaded attachment for work order %d", workOrderID), ip, requestID)
206	
207		return attachment, nil
208	}
