210	// Download retrieves the file path and metadata for an attachment.
211	// actorID and roles are used to enforce object-level authorization.
212	func (s *Service) Download(attachmentID uint64, actorID uint64, roles []string) (*Attachment, string, *common.AppError) {
213		attachment, err := s.repo.FindByID(attachmentID)
214		if err != nil {
215			return nil, "", common.NewNotFoundError("Attachment")
216		}
217	
218		// Enforce access to the parent work order.
219		if attachment.EntityType == entityTypeWorkOrder {
220			ok, err := s.canAccessWorkOrder(attachment.EntityID, actorID, roles)
221			if err != nil || !ok {
222				return nil, "", common.NewForbiddenError("you do not have access to this attachment")
223			}
224		}
225	
226		fullPath := filepath.Join(s.storageRoot, attachment.StoragePath)
227		if _, err := os.Stat(fullPath); os.IsNotExist(err) {
228			return nil, "", common.NewNotFoundError("Attachment file")
229		}
230	
231		return attachment, fullPath, nil
232	}
