234	// Delete removes an attachment's file and database record.
235	// Only the uploader, PropertyManagers, and SystemAdmins may delete attachments.
236	func (s *Service) Delete(attachmentID uint64, actorID uint64, roles []string, ip, requestID string) *common.AppError {
237		attachment, err := s.repo.FindByID(attachmentID)
238		if err != nil {
239			return common.NewNotFoundError("Attachment")
240		}
241	
242		// Authorization: must be uploader OR have a privileged role.
243		isPrivileged := false
244		for _, r := range roles {
245			if r == "PropertyManager" || r == "SystemAdmin" {
246				isPrivileged = true
247				break
248			}
249		}
250		if !isPrivileged && attachment.UploadedBy != actorID {
251			return common.NewForbiddenError("only the uploader, property managers, or system admins may delete attachments")
252		}
253	
254		// Remove the file from storage.
255		fullPath := filepath.Join(s.storageRoot, attachment.StoragePath)
256		_ = os.Remove(fullPath)
257	
258		// Delete the database record.
259		if err := s.repo.Delete(attachmentID); err != nil {
260			return common.NewInternalError("failed to delete attachment record")
261		}
262	
263		s.audit.Log(actorID, common.AuditActionDelete, "Attachment", attachment.ID,
264			fmt.Sprintf("Deleted attachment %s from entity %s/%d", attachment.UUID, attachment.EntityType, attachment.EntityID), ip, requestID)
265	
266		return nil
267	}
