285	// UploadEvidence stores an attachment for a non-work-order entity (e.g., governance reports).
286	// Validation rules are the same as Upload (JPEG/PNG, max 5 MB, max 6 per entity).
287	// Access control must be enforced by the caller before invoking this method.
288	func (s *Service) UploadEvidence(entityType string, entityID uint64, file *multipart.FileHeader, uploaderID uint64, ip, requestID string) (*Attachment, *common.AppError) {
289		if file.Size > MaxFileSize {
290			return nil, common.NewPayloadTooLargeError("file must be at most 5 MB")
291		}
292	
293		currentCount, err := s.repo.CountByEntity(entityType, entityID)
294		if err != nil {
295			return nil, common.NewInternalError("failed to check attachment count")
296		}
297		if fe := common.ValidateAttachmentCount(currentCount, 1, MaxAttachmentsPerWorkOrder); fe != nil {
298			return nil, common.NewValidationError("Validation failed", *fe)
299		}
300	
301		src, err := file.Open()
302		if err != nil {
303			return nil, common.NewInternalError("failed to open uploaded file")
304		}
305		defer src.Close()
306	
307		header := make([]byte, 512)
308		n, err := src.Read(header)
309		if err != nil && err != io.EOF {
310			return nil, common.NewInternalError("failed to read file header")
311		}
312		header = header[:n]
313	
314		detectedMIME, fe := common.ValidateFileSignature(header)
315		if fe != nil {
316			return nil, common.NewValidationError("Validation failed", *fe)
317		}
318		declaredMIME := strings.ToLower(file.Header.Get("Content-Type"))
319		if fe := common.ValidateImageMIME(declaredMIME); fe != nil {
320			return nil, common.NewValidationError("Validation failed", *fe)
321		}
322		if declaredMIME != detectedMIME {
323			return nil, common.NewValidationError("declared MIME type does not match file content")
324		}
325	
326		if _, err := src.Seek(0, io.SeekStart); err != nil {
327			return nil, common.NewInternalError("failed to reset file reader")
328		}
329	
330		hasher := sha256.New()
331		fileBytes, err := io.ReadAll(src)
332		if err != nil {
333			return nil, common.NewInternalError("failed to read file")
334		}
335		hasher.Write(fileBytes)
336	
337		fileUUID := uuid.New().String()
338		ext := strings.ToLower(filepath.Ext(file.Filename))
339		if ext == "" {
340			switch detectedMIME {
341			case "image/jpeg":
342				ext = ".jpg"
343			case "image/png":
344				ext = ".png"
345			}
346		}
347		storagePath := filepath.Join("evidence", fmt.Sprintf("%s%s", fileUUID, ext))
348		fullPath := filepath.Join(s.storageRoot, storagePath)
349	
350		if err := os.MkdirAll(filepath.Dir(fullPath), 0750); err != nil {
351			return nil, common.NewInternalError("failed to create storage directory")
352		}
353		if err := os.WriteFile(fullPath, fileBytes, 0640); err != nil {
354			return nil, common.NewInternalError("failed to save file")
355		}
356	
357		attachment := &Attachment{
358			UUID:        fileUUID,
359			EntityType:  entityType,
360			EntityID:    entityID,
361			Filename:    file.Filename,
362			StoragePath: storagePath,
363			MimeType:    detectedMIME,
364			FileSize:    uint64(file.Size),
365			SHA256Hash:  hex.EncodeToString(hasher.Sum(nil)),
366			UploadedBy:  uploaderID,
367		}
368	
369		if err := s.repo.Create(attachment); err != nil {
370			_ = os.Remove(fullPath)
371			return nil, common.NewInternalError("failed to save attachment record")
372		}
373	
374		s.audit.Log(uploaderID, common.AuditActionCreate, "Attachment", attachment.ID,
375			fmt.Sprintf("Uploaded evidence %s for %s/%d", attachment.UUID, entityType, entityID), ip, requestID)
376	
377		return attachment, nil
378	}
