89	// SendFromTemplate looks up a notification template by name, renders the subject and body
90	// using the provided data map, and creates a pending notification.
91	func (s *Service) SendFromTemplate(templateName string, recipientID uint64, data map[string]string) (*Notification, *common.AppError) {
92		tmpl, err := s.repo.FindTemplateByName(templateName)
93		if err != nil {
94			if err == gorm.ErrRecordNotFound {
95				return nil, common.NewNotFoundError("Notification template")
96			}
97			return nil, common.NewInternalError("failed to look up template")
98		}
99	
100		subject, appErr := renderTemplate("subject", tmpl.SubjectTemplate, data)
101		if appErr != nil {
102			return nil, appErr
103		}
104	
105		body, appErr := renderTemplate("body", tmpl.BodyTemplate, data)
106		if appErr != nil {
107			return nil, appErr
108		}
109	
110		n := &Notification{
111			UUID:        uuid.New().String(),
112			RecipientID: recipientID,
113			TemplateID:  &tmpl.ID,
114			Subject:     subject,
115			Body:        body,
116			Category:    tmpl.Category,
117			Status:      common.NotificationStatusPending,
118		}
119	
120		if err := s.repo.CreateNotification(n); err != nil {
121			return nil, common.NewInternalError("failed to create notification from template")
122		}
123	
124		return n, nil
125	}
