127	// SendEvent is a convenience method for event-triggered notifications.
128	// It wraps SendFromTemplate and satisfies the NotificationSender interface
129	// expected by the workorders package.
130	func (s *Service) SendEvent(eventName string, recipientID uint64, data map[string]string) error {
131		_, appErr := s.SendFromTemplate(eventName, recipientID, data)
