138	// SendEventToRole sends an event-triggered notification to all active users with the given role.
139	// Errors from individual sends are logged but do not abort the fan-out.
140	func (s *Service) SendEventToRole(eventName, role string, data map[string]string) error {
141		ids, err := s.repo.FindUserIDsByRole(role)
142		if err != nil {
143			return fmt.Errorf("SendEventToRole: failed to resolve recipients for role %q: %w", role, err)
144		}
145		for _, id := range ids {
146			if _, appErr := s.SendFromTemplate(eventName, id, data); appErr != nil {
147				// Best-effort: log individual failures but continue fan-out.
148				_ = appErr
149			}
150		}
151		return nil
152	}
