185	// MarkRead creates a receipt for the given notification and user, marking it as read.
186	func (s *Service) MarkRead(notificationID, userID uint64) *common.AppError {
187		// Verify the notification exists and belongs to the user.
188		n, err := s.repo.FindByID(notificationID)
189		if err != nil {
190			if err == gorm.ErrRecordNotFound {
191				return common.NewNotFoundError("Notification")
192			}
193			return common.NewInternalError("failed to find notification")
194		}
195	
196		if n.RecipientID != userID {
197			return common.NewForbiddenError("you can only mark your own notifications as read")
198		}
199	
200		// Check if already read.
201		existing, _ := s.repo.FindReceipt(notificationID, userID)
202		if existing != nil {
203			return nil // Already marked as read; idempotent.
204		}
205	
206		now := time.Now().UTC()
207		receipt := &NotificationReceipt{
208			NotificationID: notificationID,
209			UserID:         userID,
210			ReadAt:         &now,
211		}
212	
213		if err := s.repo.CreateReceipt(receipt); err != nil {
214			return common.NewInternalError("failed to mark notification as read")
215		}
216	
217		return nil
218	}
