250	// ListNotifications retrieves a paginated list of notifications for a user with filters.
251	func (s *Service) ListNotifications(userID uint64, filters NotificationFilters, page, perPage int) ([]Notification, []bool, int64, *common.AppError) {
252		if page < 1 {
253			page = 1
254		}
255		if perPage < 1 {
256			perPage = 20
257		}
258		if perPage > 100 {
259			perPage = 100
260		}
261	
262		offset := (page - 1) * perPage
263		notifications, total, err := s.repo.FindByRecipient(userID, filters, offset, perPage)
264		if err != nil {
265			return nil, nil, 0, common.NewInternalError("failed to list notifications")
266		}
267	
268		// Determine read status for each notification.
269		readStatuses := make([]bool, len(notifications))
270		for i, n := range notifications {
271			receipt, _ := s.repo.FindReceipt(n.ID, userID)
272			readStatuses[i] = receipt != nil
273		}
274	
275		return notifications, readStatuses, total, nil
276	}
