310	// AddThreadParticipant adds a user to an existing thread. Only current participants may invite others.
311	// The thread creator can always add participants. Adding an existing participant is a no-op.
312	func (s *Service) AddThreadParticipant(threadID, actorID, targetUserID uint64) *common.AppError {
313		// Verify the thread exists.
314		thread, err := s.repo.FindThreadByID(threadID)
315		if err != nil {
316			if err == gorm.ErrRecordNotFound {
317				return common.NewNotFoundError("Thread")
318			}
319			return common.NewInternalError("failed to find thread")
320		}
321	
322		if thread.IsClosed {
323			return common.NewValidationError("cannot add participants to a closed thread")
324		}
325	
326		// Only current participants (including the creator) may add others.
327		isParticipant, err := s.repo.IsParticipant(threadID, actorID)
328		if err != nil {
329			return common.NewInternalError("failed to check thread participation")
330		}
331		if !isParticipant {
332			return common.NewForbiddenError("only thread participants can add new participants")
333		}
334	
335		// No-op if target is already a participant.
336		already, err := s.repo.IsParticipant(threadID, targetUserID)
337		if err != nil {
338			return common.NewInternalError("failed to check target participation")
339		}
340		if already {
341			return nil // idempotent
342		}
343	
344		p := &ThreadParticipant{
345			ThreadID: threadID,
346			UserID:   targetUserID,
347			JoinedAt: time.Now().UTC(),
348		}
349		if err := s.repo.AddParticipant(p); err != nil {
350			return common.NewInternalError("failed to add participant")
351		}
352		return nil
353	}
