356	func (s *Service) GetParticipants(threadID, actorID uint64) ([]ThreadParticipant, *common.AppError) {
357		isParticipant, err := s.repo.IsParticipant(threadID, actorID)
358		if err != nil {
359			return nil, common.NewInternalError("failed to check thread participation")
360		}
361		if !isParticipant {
362			return nil, common.NewForbiddenError("only thread participants can view participants")
363		}
364	
365		participants, err := s.repo.ListParticipants(threadID)
366		if err != nil {
367			return nil, common.NewInternalError("failed to list participants")
368		}
369		return participants, nil
370	}
