373	// The sender is automatically added as a participant if not already one.
374	func (s *Service) AddMessage(threadID, senderID uint64, req AddMessageRequest) (*ThreadMessage, *common.AppError) {
375		if req.Body == "" {
376			return nil, common.NewValidationError("body is required")
377		}
378	
379		// Verify thread exists.
380		thread, err := s.repo.FindThreadByID(threadID)
381		if err != nil {
382			if err == gorm.ErrRecordNotFound {
383				return nil, common.NewNotFoundError("Thread")
384			}
385			return nil, common.NewInternalError("failed to find thread")
386		}
387	
388		if thread.IsClosed {
389			return nil, common.NewValidationError("thread is closed")
390		}
391	
392		// Check participant access.
393		isParticipant, err := s.repo.IsParticipant(threadID, senderID)
394		if err != nil {
395			return nil, common.NewInternalError("failed to check thread participation")
396		}
397		if !isParticipant {
398			return nil, common.NewForbiddenError("only thread participants can post messages")
399		}
