493	// renderTemplate parses and executes a Go text/template string with the given data.
494	func renderTemplate(name, tmplStr string, data map[string]string) (string, *common.AppError) {
495		t, err := template.New(name).Parse(tmplStr)
496		if err != nil {
497			return "", common.NewInternalError(fmt.Sprintf("failed to parse %s template: %v", name, err))
