35	// ConversionFunnel returns work-order counts for the main lifecycle statuses.
36	func (r *Repository) ConversionFunnel(filters AnalyticsFilters) (*FunnelMetric, error) {
37		type row struct {
38			Status string
39			Count  int64
40		}
41	
42		q := r.db.Table("work_orders").
43			Select("status, COUNT(*) as count").
44			Where("deleted_at IS NULL")
45	
46		q = applyWorkOrderFilters(q, filters)
47		q = q.Group("status")
48	
49		var rows []row
50		if err := q.Scan(&rows).Error; err != nil {
51			return nil, err
52		}
53	
54		m := &FunnelMetric{}
55		for _, r := range rows {
56			switch r.Status {
57			case "New":
58				m.New = r.Count
59			case "Assigned":
60				m.Assigned = r.Count
61			case "InProgress":
62				m.InProgress = r.Count
63			case "Completed":
64				m.Completed = r.Count
65			}
66			m.Total += r.Count
67		}
68		return m, nil
69	}
70	
71	// RetentionMetrics returns repeat-request counts for 30-day and 90-day windows.
72	func (r *Repository) RetentionMetrics(filters AnalyticsFilters) (*RetentionMetric, error) {
73		type unitCount struct {
74			UnitID *uint64
75			Count  int64
76		}
77	
78		retentionForDays := func(days int) (unique int64, repeat int64, err error) {
79			var rows []unitCount
80	
81			q := r.db.Table("work_orders").
82				Select("unit_id, COUNT(*) as count").
83				Where("deleted_at IS NULL AND unit_id IS NOT NULL")
84	
85			if !filters.From.IsZero() {
86				q = q.Where("created_at >= ?", filters.From)
87			} else {
88				q = q.Where("created_at >= DATE_SUB(NOW(), INTERVAL ? DAY)", days)
89			}
90			if !filters.To.IsZero() {
91				q = q.Where("created_at <= ?", filters.To)
92			}
93			if filters.PropertyID != nil {
94				q = q.Where("property_id = ?", *filters.PropertyID)
95			}
96	
97			q = q.Group("unit_id")
98	
99			if err = q.Scan(&rows).Error; err != nil {
100				return 0, 0, err
101			}
102	
103			for _, row := range rows {
104				unique++
105				if row.Count > 1 {
106					repeat++
107				}
108			}
109			return unique, repeat, nil
110		}
111	
112		unique30, repeat30, err := retentionForDays(30)
113		if err != nil {
114			return nil, err
115		}
116		unique90, repeat90, err := retentionForDays(90)
117		if err != nil {
118			return nil, err
119		}
120	
121		m := &RetentionMetric{
122			UniqueUnits30d: unique30,
123			RepeatUnits30d: repeat30,
124			UniqueUnits90d: unique90,
125			RepeatUnits90d: repeat90,
126		}
127		if unique30 > 0 {
128			m.RepeatRate30d = float64(repeat30) / float64(unique30)
129		}
130		if unique90 > 0 {
131			m.RepeatRate90d = float64(repeat90) / float64(unique90)
132		}
133		return m, nil
134	}
