1	package health
2	
3	import (
4		"net/http"
5		"os"
6	
7		"propertyops/backend/internal/config"
8	
9		"github.com/gin-gonic/gin"
10		"gorm.io/gorm"
11	)
12	
13	// LivenessResponse is the response body for GET /health/live.
14	type LivenessResponse struct {
15		Status string `json:"status"`
16	}
17	
18	// Check represents the outcome of a single readiness sub-check.
19	type Check struct {
20		Status  string `json:"status"`
21		Message string `json:"message,omitempty"`
22	}
23	
24	// ReadinessResponse is the response body for GET /health/ready.
25	type ReadinessResponse struct {
26		Status string            `json:"status"`
27		Checks map[string]Check  `json:"checks"`
28	}
29	
30	// RegisterRoutes mounts the liveness and readiness endpoints on the engine.
31	func RegisterRoutes(engine *gin.Engine, db *gorm.DB, cfg *config.Config) {
32		engine.GET("/health/live", livenessHandler())
33		engine.GET("/health/ready", readinessHandler(db, cfg))
34	}
35	
36	// livenessHandler returns 200 if the process is alive — no dependencies checked.
37	func livenessHandler() gin.HandlerFunc {
38		return func(c *gin.Context) {
39			c.JSON(http.StatusOK, LivenessResponse{Status: "ok"})
40		}
41	}
42	
43	// readinessHandler performs all dependency checks and returns 200 when all pass,
44	// or 503 when one or more checks fail.
45	func readinessHandler(db *gorm.DB, cfg *config.Config) gin.HandlerFunc {
46		return func(c *gin.Context) {
47			checks := make(map[string]Check, 4)
48			allOK := true
49	
50			// --- DB check ---
51			dbCheck := checkDB(db)
52			checks["db"] = dbCheck
53			if dbCheck.Status != "ok" {
54				allOK = false
55			}
56	
57			// --- Storage root check ---
58			storageCheck := checkDir("storage", cfg.Storage.Root)
59			checks["storage"] = storageCheck
60			if storageCheck.Status != "ok" {
61				allOK = false
62			}
63	
64			// --- Encryption key directory check ---
65			keysCheck := checkDir("keys", cfg.Encryption.KeyDir)
66			checks["keys"] = keysCheck
67			if keysCheck.Status != "ok" {
68				allOK = false
69			}
70	
71			// --- Backup directory check ---
72			backupCheck := checkDir("backup_dir", cfg.Storage.BackupRoot)
73			checks["backup_dir"] = backupCheck
74			if backupCheck.Status != "ok" {
75				allOK = false
76			}
77	
78			overallStatus := "ok"
79			statusCode := http.StatusOK
80			if !allOK {
81				overallStatus = "degraded"
82				statusCode = http.StatusServiceUnavailable
83			}
84	
85			c.JSON(statusCode, ReadinessResponse{
86				Status: overallStatus,
87				Checks: checks,
88			})
89		}
90	}
91	
92	// checkDB pings the database and returns the result as a Check.
93	func checkDB(db *gorm.DB) Check {
94		if err := db.Raw("SELECT 1").Error; err != nil {
95			return Check{Status: "fail", Message: "database unreachable: " + err.Error()}
96		}
97		return Check{Status: "ok"}
98	}
99	
100	// checkDir verifies that the given directory path is accessible via os.Stat.
101	func checkDir(name, path string) Check {
102		if path == "" {
103			return Check{Status: "fail", Message: name + " path not configured"}
104		}
105		if _, err := os.Stat(path); err != nil {
106			return Check{Status: "fail", Message: err.Error()}
107		}
108		return Check{Status: "ok"}
109	}
