22	// SecurityService is the encryption interface required by this package.
23	type SecurityService interface {
24		Encrypt(plaintext []byte) ([]byte, int, error)
25		Decrypt(ciphertext []byte, keyVersion int) ([]byte, error)
26	}
27	
