29	type AuditLogger interface {
30		Log(actorID uint64, action, resourceType string, resourceID uint64, description, ip, requestID string)
31	}
32	
33	// BackupRecord describes a backup file on disk.
34	type BackupRecord struct {
35		Filename     string    `json:"filename"`
36		FilePath     string    `json:"file_path"`
37		SizeBytes    int64     `json:"size_bytes"`
38		CreatedAt    time.Time `json:"created_at"`
39		Encrypted    bool      `json:"encrypted"`
40		ManifestPath string    `json:"manifest_path,omitempty"`
