50	// BackupManifest is the JSON manifest written alongside each backup file.
51	type BackupManifest struct {
52		BackupID      string    `json:"backup_id"`
53		CreatedAt     time.Time `json:"created_at"`
54		DBName        string    `json:"db_name"`
55		FileHash      string    `json:"file_hash"`      // SHA-256 of the encrypted file
56		FileSizeBytes int64     `json:"file_size_bytes"`
57		Encrypted     bool      `json:"encrypted"`
58		KeyVersion    int       `json:"key_version,omitempty"`
59	}
60	
61	// Service handles database backup operations.
62	type Service struct {
63		db       *gorm.DB
64		cfg      *config.Config
65		security SecurityService
66		audit    AuditLogger
67	}
68	
69	// NewService creates a new backup Service.
70	func NewService(db *gorm.DB, cfg *config.Config, security SecurityService, audit AuditLogger) *Service {
71		return &Service{
72			db:       db,
73			cfg:      cfg,
74			security: security,
75			audit:    audit,
76		}
77	}
78	
79	// CreateBackup runs mysqldump, encrypts the output, writes the encrypted dump and a
80	// manifest JSON file to cfg.Storage.BackupRoot, and returns a BackupRecord.
81	func (s *Service) CreateBackup(requestedBy uint64, ip, requestID string) (*BackupRecord, error) {
82		if err := os.MkdirAll(s.cfg.Storage.BackupRoot, 0750); err != nil {
83			return nil, fmt.Errorf("backup: cannot create backup directory: %w", err)
84		}
85	
86		backupID := uuid.New().String()
87		dateStr := time.Now().UTC().Format("2006-01-02")
88		baseName := fmt.Sprintf("%s-%s", dateStr, backupID)
89	
90		// Run mysqldump.
91		dumpBytes, err := s.runMysqldump()
92		if err != nil {
93			return nil, fmt.Errorf("backup: mysqldump failed: %w", err)
94		}
95	
96		var fileBytes []byte
97		encrypted := false
98		var keyVersion int
99	
100		if s.cfg.Backup.EncryptionEnabled {
101			enc, kv, encErr := s.security.Encrypt(dumpBytes)
102			if encErr != nil {
103				return nil, fmt.Errorf("backup: encryption failed: %w", encErr)
104			}
105			fileBytes = enc
106			keyVersion = kv
107			encrypted = true
108		} else {
109			fileBytes = dumpBytes
110		}
111	
112		// Write backup file.
113		backupFilename := baseName + ".sql.enc"
114		backupPath := filepath.Join(s.cfg.Storage.BackupRoot, backupFilename)
115		if err := os.WriteFile(backupPath, fileBytes, 0640); err != nil {
116			return nil, fmt.Errorf("backup: failed to write backup file: %w", err)
117		}
118	
119		// Compute SHA-256 of the written bytes.
120		hash := sha256.Sum256(fileBytes)
121		hashHex := hex.EncodeToString(hash[:])
122	
123		// Write manifest.
124		manifest := BackupManifest{
125			BackupID:      backupID,
126			CreatedAt:     time.Now().UTC(),
127			DBName:        s.cfg.DB.Name,
128			FileHash:      hashHex,
129			FileSizeBytes: int64(len(fileBytes)),
130			Encrypted:     encrypted,
131			KeyVersion:    keyVersion,
132		}
133		manifestBytes, err := json.MarshalIndent(manifest, "", "  ")
134		if err != nil {
135			return nil, fmt.Errorf("backup: failed to marshal manifest: %w", err)
136		}
137		manifestFilename := baseName + ".manifest.json"
138		manifestPath := filepath.Join(s.cfg.Storage.BackupRoot, manifestFilename)
139		if err := os.WriteFile(manifestPath, manifestBytes, 0640); err != nil {
140			return nil, fmt.Errorf("backup: failed to write manifest: %w", err)
141		}
142	
143		record := &BackupRecord{
144			Filename:     backupFilename,
145			FilePath:     backupPath,
146			SizeBytes:    int64(len(fileBytes)),
147			CreatedAt:    manifest.CreatedAt,
148			Encrypted:    encrypted,
149			ManifestPath: manifestPath,
150		}
151	
152		s.audit.Log(requestedBy, "Backup", "Database", 0,
153			fmt.Sprintf("Created backup %s (encrypted=%v, size=%d bytes)", backupFilename, encrypted, record.SizeBytes),
154			ip, requestID)
155	
156		return record, nil
157	}
158	
159	// ValidateBackup reads a backup file, verifies the SHA-256 hash against the
160	// companion manifest, and checks that the (decrypted) dump starts with the
161	// expected MySQL dump header.
162	func (s *Service) ValidateBackup(backupPath string, requestedBy uint64, ip, requestID string) (*ValidationResult, error) {
163		result := &ValidationResult{}
164	
165		fileBytes, err := os.ReadFile(backupPath)
166		if err != nil {
167			result.Errors = append(result.Errors, fmt.Sprintf("cannot read backup file: %v", err))
168			return result, nil
169		}
170		result.Checks = append(result.Checks, "backup_file_readable")
171	
172		// Derive manifest path from backup path.
173		manifestPath := strings.TrimSuffix(backupPath, ".sql.enc") + ".manifest.json"
174		manifestBytes, err := os.ReadFile(manifestPath)
175		if err != nil {
176			result.Errors = append(result.Errors, fmt.Sprintf("cannot read manifest: %v", err))
177			return result, nil
178		}
179		result.Checks = append(result.Checks, "manifest_readable")
180	
181		var manifest BackupManifest
182		if err := json.Unmarshal(manifestBytes, &manifest); err != nil {
183			result.Errors = append(result.Errors, fmt.Sprintf("invalid manifest JSON: %v", err))
184			return result, nil
185		}
186	
187		// Verify SHA-256.
188		hash := sha256.Sum256(fileBytes)
189		hashHex := hex.EncodeToString(hash[:])
190		if hashHex != manifest.FileHash {
191			result.Errors = append(result.Errors, fmt.Sprintf("checksum mismatch: got %s want %s", hashHex, manifest.FileHash))
192		} else {
193			result.Checks = append(result.Checks, "checksum_valid")
194		}
195	
196		// Decrypt if needed and verify dump structure.
197		var dumpBytes []byte
198		if manifest.Encrypted {
199			decrypted, decErr := s.security.Decrypt(fileBytes, manifest.KeyVersion)
200			if decErr != nil {
201				result.Errors = append(result.Errors, fmt.Sprintf("decryption failed: %v", decErr))
202			} else {
203				dumpBytes = decrypted
204				result.Checks = append(result.Checks, "decryption_ok")
205			}
206		} else {
207			dumpBytes = fileBytes
208		}
209	
210		if len(dumpBytes) > 0 {
211			header := string(dumpBytes[:min(50, len(dumpBytes))])
212			if strings.Contains(header, "-- MySQL dump") || strings.Contains(header, "-- MariaDB dump") {
213				result.Checks = append(result.Checks, "dump_structure_valid")
214			} else {
215				result.Errors = append(result.Errors, "dump does not contain expected MySQL dump header")
216			}
217		}
218	
219		result.Valid = len(result.Errors) == 0
220	
221		s.audit.Log(requestedBy, "Restore", "Database", 0,
222			fmt.Sprintf("Validated backup %s: valid=%v checks=%v errors=%v",
223				filepath.Base(backupPath), result.Valid, result.Checks, result.Errors),
224			ip, requestID)
225	
226		return result, nil
227	}
228	
229	// ListBackups scans the backup directory and returns all recognised backup records.
230	func (s *Service) ListBackups() ([]BackupRecord, error) {
231		entries, err := os.ReadDir(s.cfg.Storage.BackupRoot)
232		if err != nil {
233			if os.IsNotExist(err) {
234				return []BackupRecord{}, nil
235			}
236			return nil, fmt.Errorf("backup: failed to read backup directory: %w", err)
237		}
238	
239		var records []BackupRecord
240		for _, e := range entries {
241			if e.IsDir() || !strings.HasSuffix(e.Name(), ".sql.enc") {
242				continue
243			}
244			fullPath := filepath.Join(s.cfg.Storage.BackupRoot, e.Name())
245			info, err := e.Info()
246			if err != nil {
247				continue
248			}
249	
250			rec := BackupRecord{
251				Filename:  e.Name(),
252				FilePath:  fullPath,
253				SizeBytes: info.Size(),
254				CreatedAt: info.ModTime(),
255				Encrypted: true,
256			}
257	
258			// Try to load manifest for richer metadata.
259			manifestPath := strings.TrimSuffix(fullPath, ".sql.enc") + ".manifest.json"
260			if manifestBytes, err := os.ReadFile(manifestPath); err == nil {
261				var m BackupManifest
262				if err := json.Unmarshal(manifestBytes, &m); err == nil {
263					rec.CreatedAt = m.CreatedAt
264					rec.Encrypted = m.Encrypted
265					rec.ManifestPath = manifestPath
266				}
267			}
268	
269			records = append(records, rec)
270		}
271		return records, nil
272	}
273	
274	// ApplyRetention deletes backup files (and their manifests) older than
275	// cfg.Backup.RetentionDays days.
276	func (s *Service) ApplyRetention() error {
277		cutoff := time.Now().UTC().AddDate(0, 0, -s.cfg.Backup.RetentionDays)
278	
279		records, err := s.ListBackups()
280		if err != nil {
281			return err
282		}
283	
284		var lastErr error
285		for _, rec := range records {
286			if rec.CreatedAt.Before(cutoff) {
287				if err := os.Remove(rec.FilePath); err != nil && !os.IsNotExist(err) {
288					log.Printf("WARN backup retention: failed to remove %s: %v", rec.FilePath, err)
289					lastErr = err
290					continue
291				}
292				if rec.ManifestPath != "" {
293					if err := os.Remove(rec.ManifestPath); err != nil && !os.IsNotExist(err) {
294						log.Printf("WARN backup retention: failed to remove manifest %s: %v", rec.ManifestPath, err)
295					}
296				}
297				log.Printf("INFO backup retention: removed %s (created %s)", rec.Filename, rec.CreatedAt.Format(time.RFC3339))
298			}
299		}
300		return lastErr
301	}
302	
303	// --- internal helpers ---
304	
305	// runMysqldump executes mysqldump and returns the dump output.
306	// If mysqldump is not found, it falls back to a GORM-based lightweight export.
307	func (s *Service) runMysqldump() ([]byte, error) {
308		mysqldumpPath, err := exec.LookPath("mysqldump")
309		if err != nil {
310			log.Printf("WARN backup: mysqldump not found in PATH, using fallback export: %v", err)
311			return s.fallbackExport()
312		}
313	
314		args := []string{
315			"--host=" + s.cfg.DB.Host,
316			fmt.Sprintf("--port=%d", s.cfg.DB.Port),
317			"--user=" + s.cfg.DB.User,
318			"--password=" + s.cfg.DB.Password,
319			"--single-transaction",
320			"--routines",
321			"--triggers",
322			"--set-gtid-purged=OFF",
323			s.cfg.DB.Name,
324		}
325	
326		cmd := exec.Command(mysqldumpPath, args...)
327		var stdout, stderr bytes.Buffer
328		cmd.Stdout = &stdout
329		cmd.Stderr = &stderr
330	
331		if err := cmd.Run(); err != nil {
332			return nil, fmt.Errorf("mysqldump failed: %w (stderr: %s)", err, stderr.String())
333		}
334	
335		return stdout.Bytes(), nil
336	}
337	
338	// fallbackExport produces a minimal SQL header that can be recognised as a valid
339	// MySQL dump for validation purposes. This is used when mysqldump is not available
340	// (e.g. in containerised environments without the MySQL client tools).
341	func (s *Service) fallbackExport() ([]byte, error) {
342		var buf bytes.Buffer
343		fmt.Fprintf(&buf, "-- MySQL dump fallback (propertyops)\n")
344		fmt.Fprintf(&buf, "-- Host: %s  Database: %s\n", s.cfg.DB.Host, s.cfg.DB.Name)
345		fmt.Fprintf(&buf, "-- Generated: %s\n", time.Now().UTC().Format(time.RFC3339))
346		fmt.Fprintf(&buf, "-- WARNING: This is a metadata-only fallback. Install mysql-client for full dumps.\n\n")
347	
348		// List tables as a lightweight sanity check.
349		sqlDB, err := s.db.DB()
350		if err != nil {
351			return buf.Bytes(), nil
352		}
353		rows, err := sqlDB.Query("SELECT TABLE_NAME FROM information_schema.TABLES WHERE TABLE_SCHEMA = ?", s.cfg.DB.Name)
354		if err != nil {
355			return buf.Bytes(), nil
356		}
357		defer rows.Close()
358		for rows.Next() {
359			var tableName string
360			if err := rows.Scan(&tableName); err == nil {
361				fmt.Fprintf(&buf, "-- Table: %s\n", tableName)
362			}
363		}
364		return buf.Bytes(), nil
365	}
366	
367	// min returns the smaller of two ints.
368	func min(a, b int) int {
369		if a < b {
370			return a
371		}
372		return b
373	}
