72		var fieldErrors []*common.FieldError
73	
74		if fe := common.ValidateReportTargetType(req.TargetType); fe != nil {
75			fieldErrors = append(fieldErrors, fe)
76		}
77		if req.TargetID == 0 {
78			fieldErrors = append(fieldErrors, &common.FieldError{Field: "target_id", Message: "is required"})
79		}
80		if !validReportCategories[req.Category] {
81			fieldErrors = append(fieldErrors, &common.FieldError{
82				Field:   "category",
83				Message: fmt.Sprintf("must be one of: Harassment, Damage, Noise, Maintenance, Fraud, Other"),
84			})
85		}
86		if fe := common.ValidateDescription(req.Description); fe != nil {
87			fieldErrors = append(fieldErrors, fe)
88		}
89	
90		if appErr := common.CollectFieldErrors(fieldErrors...); appErr != nil {
91			return nil, appErr
92		}
93	
94		// Check blacklist on the description.
95		matched, err := s.repo.CheckContent(req.Description)
96		if err == nil && len(matched) > 0 {
97			// Flag content but still create the report; the matched keywords are noted.
98			// We continue creating the report as it is a moderation report itself.
99		}
100	
101		report := &Report{
102			UUID:        uuid.New().String(),
103			ReporterID:  reporterID,
104			TargetType:  req.TargetType,
105			TargetID:    req.TargetID,
106			Category:    req.Category,
107			Description: req.Description,
108			Status:      common.ReportStatusOpen,
109		}
110	
111		if err := s.repo.CreateReport(report); err != nil {
112			return nil, common.NewInternalError("failed to create report")
113		}
114	
115		// Audit log.
116		s.audit.Log(reporterID, common.AuditActionCreate, "Report", report.ID,
117			fmt.Sprintf("Report created against %s #%d", req.TargetType, req.TargetID), ip, requestID)
118	
119		// Notify all active ComplianceReviewer users about the new report.
120		if s.notifier != nil {
121			if err := s.notifier.SendEventToRole("report_filed", common.RoleComplianceReviewer, map[string]string{
122				"report_id":   fmt.Sprintf("%d", report.ID),
123				"target_type": report.TargetType,
124				"target_id":   fmt.Sprintf("%d", report.TargetID),
125				"category":    report.Category,
126			}); err != nil {
127				log.Printf("WARN governance: notification fan-out failed for report_filed (report %d): %v", report.ID, err)
128			}
129		}
130	
131		return report, nil
132	}
