173	// ReviewReport transitions a report's status; only ComplianceReviewer or SystemAdmin may call.
174	func (s *Service) ReviewReport(reportID uint64, req ReviewReportRequest, reviewerID uint64, ip, requestID string) (*Report, *common.AppError) {
175		// Validate target status.
176		switch req.Status {
177		case common.ReportStatusInReview, common.ReportStatusResolved, common.ReportStatusDismissed:
178			// valid
179		default:
180			return nil, common.NewValidationError("status must be InReview, Resolved, or Dismissed")
181		}
182	
183		report, appErr := s.GetReport(reportID)
184		if appErr != nil {
185			return nil, appErr
186		}
187	
188		// Validate transition: Open -> InReview -> Resolved/Dismissed.
189		if !isValidReportTransition(report.Status, req.Status) {
190			return nil, common.NewValidationError(
191				fmt.Sprintf("invalid transition from %s to %s", report.Status, req.Status),
192			)
193		}
194	
195		report.Status = req.Status
196		report.ReviewerID = &reviewerID
197	
198		if req.Status == common.ReportStatusResolved || req.Status == common.ReportStatusDismissed {
199			now := time.Now().UTC()
200			report.ResolvedAt = &now
201			if req.ResolutionNotes != "" {
202				report.ResolutionNotes = &req.ResolutionNotes
203			}
204		}
205	
206		if err := s.repo.UpdateReportStatus(report); err != nil {
207			return nil, common.NewInternalError("failed to update report status")
208		}
209	
210		s.audit.Log(reviewerID, common.AuditActionStatusChange, "Report", report.ID,
211			fmt.Sprintf("Report status changed to %s", req.Status), ip, requestID)
212	
213		return report, nil
214	}
215	
216	// isValidReportTransition checks allowed report status transitions.
217	func isValidReportTransition(from, to string) bool {
218		switch from {
219		case common.ReportStatusOpen:
220			return to == common.ReportStatusInReview || to == common.ReportStatusDismissed
221		case common.ReportStatusInReview:
222			return to == common.ReportStatusResolved || to == common.ReportStatusDismissed
223		default:
224			return false
225		}
226	}
