567	// EvaluateRiskRules evaluates content against active risk rules and auto-creates enforcement if triggered.
568	func (s *Service) EvaluateRiskRules(content string, userID uint64, ip, requestID string) (*RiskResult, *common.AppError) {
569		result := s.riskEngine.EvaluateContent(content, userID)
570	
571		// Auto-apply enforcement if risk score is high enough and rules were matched.
572		for _, matched := range result.MatchedRules {
573			if matched.ActionType == common.EnforcementWarning ||
574				matched.ActionType == common.EnforcementRateLimit ||
575				matched.ActionType == common.EnforcementSuspension {
576				_, _ = s.ApplyEnforcement(CreateEnforcementRequest{
577					UserID:     userID,
578					ActionType: matched.ActionType,
579					Reason:     fmt.Sprintf("Auto-enforcement triggered by risk rule: %s", matched.RuleName),
580				}, 0, ip, requestID) // actorID=0 means system-initiated
581			}
582		}
583	
584		return result, nil
585	}
