105	// UpdateProfile updates an existing tenant profile with object-level authorization.
106	func (s *Service) UpdateProfile(profileID uint64, req UpdateTenantProfileRequest, actorID uint64, roles []string, ip, requestID string) (*TenantProfileResponse, *common.AppError) {
107		profile, err := s.repo.FindByID(profileID)
108		if err != nil {
109			if errors.Is(err, gorm.ErrRecordNotFound) {
110				return nil, common.NewNotFoundError("TenantProfile")
111			}
112			return nil, common.NewInternalError("failed to find tenant profile")
113		}
114	
115		// Object-level auth: tenants can only update their own profile
116		if !s.canAccessProfile(actorID, roles, profile) {
117			return nil, common.NewForbiddenError("you can only update your own profile")
118		}
119	
120		if req.UnitID != nil {
121			profile.UnitID = req.UnitID
122		}
123		if req.EmergencyContact != nil {
124			contact := *req.EmergencyContact
125			if contact == "" {
126				profile.EmergencyContactEncrypted = nil
127				profile.EmergencyContactKeyVersion = nil
128			} else {
129				encrypted, keyVer, encErr := s.encryptor.Encrypt([]byte(contact))
130				if encErr != nil {
131					return nil, common.NewInternalError("failed to encrypt emergency contact")
132				}
133				profile.EmergencyContactEncrypted = encrypted
134				profile.EmergencyContactKeyVersion = &keyVer
135			}
136		}
137		if req.LeaseStart != nil {
138			if *req.LeaseStart == "" {
139				profile.LeaseStart = nil
140			} else {
141				t, parseErr := time.Parse("2006-01-02", *req.LeaseStart)
142				if parseErr != nil {
143					return nil, common.NewValidationError("Validation failed",
144						common.FieldError{Field: "lease_start", Message: "must be in YYYY-MM-DD format"})
145				}
146				profile.LeaseStart = &t
147			}
148		}
149		if req.LeaseEnd != nil {
150			if *req.LeaseEnd == "" {
151				profile.LeaseEnd = nil
152			} else {
153				t, parseErr := time.Parse("2006-01-02", *req.LeaseEnd)
154				if parseErr != nil {
155					return nil, common.NewValidationError("Validation failed",
156						common.FieldError{Field: "lease_end", Message: "must be in YYYY-MM-DD format"})
157				}
158				profile.LeaseEnd = &t
159			}
160		}
161		if req.MoveInDate != nil {
162			if *req.MoveInDate == "" {
163				profile.MoveInDate = nil
164			} else {
165				t, parseErr := time.Parse("2006-01-02", *req.MoveInDate)
166				if parseErr != nil {
167					return nil, common.NewValidationError("Validation failed",
168						common.FieldError{Field: "move_in_date", Message: "must be in YYYY-MM-DD format"})
169				}
170				profile.MoveInDate = &t
171			}
172		}
173		if req.Notes != nil {
174			if *req.Notes == "" {
175				profile.Notes = nil
176			} else {
177				profile.Notes = req.Notes
178			}
179		}
180	
181		if err := s.repo.Update(profile); err != nil {
182			return nil, common.NewInternalError("failed to update tenant profile")
183		}
184	
185		s.audit.Log(actorID, common.AuditActionUpdate, "TenantProfile", profile.ID,
186			fmt.Sprintf("Updated tenant profile %d", profile.ID), ip, requestID)
187	
188		contact := s.decryptContact(profile)
189		resp := ToTenantProfileResponse(profile, contact, actorID == profile.UserID)
190		return &resp, nil
191	}
