259	// canAccessProfile checks if the actor has permission to access the tenant profile.
260	// Tenants can only access their own profile. SystemAdmin can access any. PropertyManager
261	// can only access profiles for tenants whose unit belongs to a property they manage.
262	func (s *Service) canAccessProfile(actorID uint64, roles []string, profile *TenantProfile) bool {
263		// Owner can always access their own profile.
264		if actorID == profile.UserID {
265			return true
266		}
267		// SystemAdmin can access any profile.
268		if hasRole(roles, common.RoleSystemAdmin) {
269			return true
270		}
271		// PropertyManager may only access profiles for tenants in their managed properties.
272		if hasRole(roles, common.RolePropertyManager) && profile.UnitID != nil {
273			return s.repo.IsPMForUnit(*profile.UnitID, actorID)
274		}
275		return false
276	}
