278	// decryptContact decrypts the emergency contact field if present.
279	func (s *Service) decryptContact(profile *TenantProfile) string {
280		if profile.EmergencyContactEncrypted == nil || profile.EmergencyContactKeyVersion == nil {
281			return ""
282		}
283		decrypted, err := s.encryptor.Decrypt(profile.EmergencyContactEncrypted, *profile.EmergencyContactKeyVersion)
284		if err != nil {
285			return ""
286		}
287		return string(decrypted)
288	}
