283	// Reassign reassigns a work order to a different technician with a required reason.
284	func (s *Service) Reassign(woID uint64, req ReassignRequest, actorID uint64, ip, requestID string) (*WorkOrder, *common.AppError) {
285		// Validate reason length.
286		if fe := common.ValidateReassignReason(req.Reason); fe != nil {
287			return nil, common.NewValidationError("Validation failed", *fe)
288		}
289	
290		wo, appErr := s.GetByID(woID)
291		if appErr != nil {
292			return nil, appErr
293		}
294	
295		// Work order must be in Assigned or InProgress to reassign.
296		if wo.Status != common.WOStatusAssigned && wo.Status != common.WOStatusInProgress {
297			return nil, common.NewValidationError("work order must be in Assigned or InProgress status to reassign")
298		}
299	
300		previousAssignee := wo.AssignedTo
301		wo.AssignedTo = &req.TechnicianID
302		wo.Status = common.WOStatusAssigned
303	
304		if err := s.repo.Update(wo); err != nil {
305			return nil, common.NewInternalError("failed to reassign work order")
306		}
307	
308		metadata := map[string]interface{}{
309			"previous_assignee": previousAssignee,
310			"new_assignee":      req.TechnicianID,
311			"reason":            req.Reason,
312		}
313		metaJSON, _ := json.Marshal(metadata)
314	
315		s.createEvent(wo.ID, &actorID, "reassigned", "", common.WOStatusAssigned,
316			fmt.Sprintf("Reassigned to technician %d: %s", req.TechnicianID, req.Reason),
317			metaJSON)
318	
319		s.audit.Log(actorID, common.AuditActionUpdate, "WorkOrder", wo.ID,
320			fmt.Sprintf("Reassigned to technician %d: %s", req.TechnicianID, req.Reason), ip, requestID)
321	
322		// Notify new assignee.
323		if s.notifier != nil {
324			_ = s.notifier.SendEvent("work_order_assigned", req.TechnicianID, map[string]string{
325				"work_order_id": fmt.Sprintf("%d", wo.ID),
326				"priority":      wo.Priority,
327			})
328		}
329	
330		return wo, nil
331	}
