333	// AddCostItem validates and adds a cost item to a work order.
334	func (s *Service) AddCostItem(woID uint64, req AddCostItemRequest, actorID uint64, ip, requestID string) (*CostItem, *common.AppError) {
335		// Validate fields.
336		var fieldErrors []*common.FieldError
337		if fe := common.ValidateCostType(req.CostType); fe != nil {
338			fieldErrors = append(fieldErrors, fe)
