342		}
343		if fe := common.ValidateMoneyAmount("amount", req.Amount); fe != nil {
344			fieldErrors = append(fieldErrors, fe)
345		}
346		if req.Description == "" {
347			fieldErrors = append(fieldErrors, &common.FieldError{Field: "description", Message: "is required"})
348		}
349		if appErr := common.CollectFieldErrors(fieldErrors...); appErr != nil {
350			return nil, appErr
351		}
352	
353		// Verify work order exists.
354		if _, appErr := s.GetByID(woID); appErr != nil {
355			return nil, appErr
356		}
357	
358		var notes *string
359		if req.Notes != "" {
360			notes = &req.Notes
361		}
362	
363		item := &CostItem{
364			UUID:           uuid.New().String(),
365			WorkOrderID:    woID,
366			CostType:       req.CostType,
367			Description:    req.Description,
368			Amount:         req.Amount,
369			Responsibility: req.Responsibility,
370			Notes:          notes,
371			CreatedBy:      actorID,
372		}
