374		if err := s.repo.CreateCostItem(item); err != nil {
375			return nil, common.NewInternalError("failed to add cost item")
376		}
377	
378		s.createEvent(woID, &actorID, "cost_item_added", "", "",
379			fmt.Sprintf("Cost item added: %s $%.2f", req.CostType, req.Amount), nil)
