491	// CalculateSLA computes the SLA due time based on priority and the given start time.
492	func CalculateSLA(priority string, from time.Time) time.Time {
493		switch priority {
494		case common.PriorityEmergency:
495			return from.Add(4 * time.Hour)
496		case common.PriorityHigh:
497			return from.Add(24 * time.Hour)
498		case common.PriorityNormal:
499			return from.Add(72 * time.Hour)
500		case common.PriorityLow:
501			return addBusinessDays(from, 5)
502		default:
503			return from.Add(72 * time.Hour)
504		}
505	}
506	
507	// addBusinessDays adds the specified number of business days (Mon-Fri) to the given time.
508	func addBusinessDays(from time.Time, days int) time.Time {
509		added := 0
510		current := from
511		for added < days {
512			current = current.Add(24 * time.Hour)
513			weekday := current.Weekday()
514			if weekday != time.Saturday && weekday != time.Sunday {
515				added++
516			}
517		}
518		return current
519	}
