370	// --- Authorization helpers ---
371	
372	// authorizeView checks if the current user is allowed to view the work order.
373	func (h *Handler) authorizeView(c *gin.Context, wo *WorkOrder) *common.AppError {
374		userID := c.GetUint64(string(common.CtxKeyUserID))
375		roles := c.GetStringSlice(string(common.CtxKeyRoles))
376	
377		// SystemAdmin can view everything.
378		if hasRole(roles, common.RoleSystemAdmin) {
379			return nil
380		}
381	
382		// PropertyManager can only view work orders on properties they manage.
383		if hasRole(roles, common.RolePropertyManager) {
384			managed, err := h.service.IsManagedBy(wo.PropertyID, userID)
385			if err != nil || !managed {
386				return common.NewForbiddenError("you do not manage the property for this work order")
387			}
388			return nil
389		}
390	
391		// Tenant can only view own work orders.
392		if hasRole(roles, common.RoleTenant) && wo.TenantID == userID {
393			return nil
394		}
395	
396		// Technician can view assigned work orders.
397		if hasRole(roles, common.RoleTechnician) && wo.AssignedTo != nil && *wo.AssignedTo == userID {
398			return nil
399		}
400	
401		return common.NewForbiddenError("you do not have access to this work order")
402	}
403	
404	// authorizeTransition checks if the current user is allowed to perform the transition.
405	func (h *Handler) authorizeTransition(c *gin.Context, wo *WorkOrder, toStatus string, userID uint64, roles []string) *common.AppError {
406		_ = c // included for consistency; roles/userID already extracted
407	
408		// SystemAdmin can do anything.
409		if hasRole(roles, common.RoleSystemAdmin) {
410			return nil
411		}
412	
413		// PropertyManager can approve/reject (AwaitingApproval -> Completed or InProgress) and archive,
414		// but only for work orders on properties they manage.
415		if hasRole(roles, common.RolePropertyManager) {
416			managed, err := h.service.IsManagedBy(wo.PropertyID, userID)
417			if err != nil || !managed {
418				return common.NewForbiddenError("you do not manage the property for this work order")
419			}
420			return nil
421		}
422	
423		// Technician can transition their own assigned work orders (Assigned->InProgress, InProgress->AwaitingApproval).
424		if hasRole(roles, common.RoleTechnician) {
425			if wo.AssignedTo == nil || *wo.AssignedTo != userID {
426				return common.NewForbiddenError("you can only transition work orders assigned to you")
427			}
428			if toStatus == common.WOStatusInProgress || toStatus == common.WOStatusAwaitingApproval {
429				return nil
430			}
431			return common.NewForbiddenError("technicians can only move to InProgress or AwaitingApproval")
432		}
433	
434		return common.NewForbiddenError("insufficient permissions for this transition")
435	}
