4		"gorm.io/gorm"
5	)
6	
7	// Repository handles all database queries for the analytics package.
8	type Repository struct {
9		db *gorm.DB
10	}
11	
12	// NewRepository creates a new analytics Repository.
13	func NewRepository(db *gorm.DB) *Repository {
14		return &Repository{db: db}
15	}
16	
17	// PopularityMetrics returns work-order counts grouped by issue_type, ordered by
18	// count descending.
19	func (r *Repository) PopularityMetrics(filters AnalyticsFilters) ([]PopularityMetric, error) {
20		q := r.db.Table("work_orders").
21			Select("issue_type, COUNT(*) as count").
22			Where("deleted_at IS NULL AND issue_type != ''")
23	
24		q = applyWorkOrderFilters(q, filters)
25	
26		q = q.Group("issue_type").Order("count DESC")
27	
28		var results []PopularityMetric
29		if err := q.Scan(&results).Error; err != nil {
30			return nil, err
31		}
32		return results, nil
33	}
34	
35	// ConversionFunnel returns work-order counts for the main lifecycle statuses.
36	func (r *Repository) ConversionFunnel(filters AnalyticsFilters) (*FunnelMetric, error) {
37		type row struct {
38			Status string
39			Count  int64
40		}
41	
42		q := r.db.Table("work_orders").
43			Select("status, COUNT(*) as count").
44			Where("deleted_at IS NULL")
45	
46		q = applyWorkOrderFilters(q, filters)
47		q = q.Group("status")
48	
49		var rows []row
50		if err := q.Scan(&rows).Error; err != nil {
51			return nil, err
52		}
53	
54		m := &FunnelMetric{}
55		for _, r := range rows {
56			switch r.Status {
57			case "New":
58				m.New = r.Count
59			case "Assigned":
60				m.Assigned = r.Count
61			case "InProgress":
62				m.InProgress = r.Count
63			case "Completed":
64				m.Completed = r.Count
65			}
66			m.Total += r.Count
67		}
68		return m, nil
69	}
