153	// QualityMetrics returns aggregated rating and reporting quality data.
154	func (r *Repository) QualityMetrics(filters AnalyticsFilters) (*QualityMetric, error) {
155		type ratingAgg struct {
156			TotalRated    int64
157			AvgRating     float64
158			NegativeCount int64
159		}
160	
161		var agg ratingAgg
162		q := r.db.Table("work_orders").
163			Select("COUNT(rating) as total_rated, AVG(rating) as avg_rating, SUM(CASE WHEN rating <= 2 THEN 1 ELSE 0 END) as negative_count").
164			Where("deleted_at IS NULL AND rating IS NOT NULL")
165	
166		q = applyWorkOrderFilters(q, filters)
167	
168		if err := q.Scan(&agg).Error; err != nil {
169			return nil, err
170		}
171	
172		// Count governance reports linked to work orders.
173		var reportedCount int64
174		rq := r.db.Table("reports").
175			Where("target_type = 'WorkOrder'")
176		if filters.PropertyID != nil {
177			rq = rq.Where("EXISTS (SELECT 1 FROM work_orders wo WHERE wo.id = reports.target_id AND wo.property_id = ?)", *filters.PropertyID)
178		}
179		_ = rq.Count(&reportedCount).Error // best-effort
180	
181		m := &QualityMetric{
182			TotalRated:    agg.TotalRated,
183			AverageRating: agg.AvgRating,
184			NegativeCount: agg.NegativeCount,
185			ReportedCount: reportedCount,
186		}
187		if agg.TotalRated > 0 {
188			m.NegativeRate = float64(agg.NegativeCount) / float64(agg.TotalRated)
189		}
190		return m, nil
191	}
