79	// CreateBackup runs mysqldump, encrypts the output, writes the encrypted dump and a
80	// manifest JSON file to cfg.Storage.BackupRoot, and returns a BackupRecord.
81	func (s *Service) CreateBackup(requestedBy uint64, ip, requestID string) (*BackupRecord, error) {
82		if err := os.MkdirAll(s.cfg.Storage.BackupRoot, 0750); err != nil {
83			return nil, fmt.Errorf("backup: cannot create backup directory: %w", err)
84		}
85	
86		backupID := uuid.New().String()
87		dateStr := time.Now().UTC().Format("2006-01-02")
88		baseName := fmt.Sprintf("%s-%s", dateStr, backupID)
89	
90		// Run mysqldump.
91		dumpBytes, err := s.runMysqldump()
92		if err != nil {
93			return nil, fmt.Errorf("backup: mysqldump failed: %w", err)
94		}
95	
96		var fileBytes []byte
97		encrypted := false
98		var keyVersion int
99	
100		if s.cfg.Backup.EncryptionEnabled {
101			enc, kv, encErr := s.security.Encrypt(dumpBytes)
102			if encErr != nil {
103				return nil, fmt.Errorf("backup: encryption failed: %w", encErr)
104			}
105			fileBytes = enc
106			keyVersion = kv
107			encrypted = true
108		} else {
109			fileBytes = dumpBytes
110		}
111	
112		// Write backup file.
113		backupFilename := baseName + ".sql.enc"
114		backupPath := filepath.Join(s.cfg.Storage.BackupRoot, backupFilename)
115		if err := os.WriteFile(backupPath, fileBytes, 0640); err != nil {
116			return nil, fmt.Errorf("backup: failed to write backup file: %w", err)
117		}
118	
119		// Compute SHA-256 of the written bytes.
120		hash := sha256.Sum256(fileBytes)
121		hashHex := hex.EncodeToString(hash[:])
122	
123		// Write manifest.
124		manifest := BackupManifest{
125			BackupID:      backupID,
126			CreatedAt:     time.Now().UTC(),
127			DBName:        s.cfg.DB.Name,
128			FileHash:      hashHex,
129			FileSizeBytes: int64(len(fileBytes)),
130			Encrypted:     encrypted,
131			KeyVersion:    keyVersion,
132		}
133		manifestBytes, err := json.MarshalIndent(manifest, "", "  ")
134		if err != nil {
135			return nil, fmt.Errorf("backup: failed to marshal manifest: %w", err)
136		}
137		manifestFilename := baseName + ".manifest.json"
138		manifestPath := filepath.Join(s.cfg.Storage.BackupRoot, manifestFilename)
139		if err := os.WriteFile(manifestPath, manifestBytes, 0640); err != nil {
140			return nil, fmt.Errorf("backup: failed to write manifest: %w", err)
141		}
142	
143		record := &BackupRecord{
144			Filename:     backupFilename,
145			FilePath:     backupPath,
146			SizeBytes:    int64(len(fileBytes)),
147			CreatedAt:    manifest.CreatedAt,
148			Encrypted:    encrypted,
149			ManifestPath: manifestPath,
150		}
151	
152		s.audit.Log(requestedBy, "Backup", "Database", 0,
153			fmt.Sprintf("Created backup %s (encrypted=%v, size=%d bytes)", backupFilename, encrypted, record.SizeBytes),
154			ip, requestID)
155	
156		return record, nil
157	}
