229	// ListBackups scans the backup directory and returns all recognised backup records.
230	func (s *Service) ListBackups() ([]BackupRecord, error) {
231		entries, err := os.ReadDir(s.cfg.Storage.BackupRoot)
232		if err != nil {
233			if os.IsNotExist(err) {
234				return []BackupRecord{}, nil
235			}
236			return nil, fmt.Errorf("backup: failed to read backup directory: %w", err)
237		}
238	
239		var records []BackupRecord
240		for _, e := range entries {
241			if e.IsDir() || !strings.HasSuffix(e.Name(), ".sql.enc") {
242				continue
243			}
244			fullPath := filepath.Join(s.cfg.Storage.BackupRoot, e.Name())
245			info, err := e.Info()
246			if err != nil {
247				continue
248			}
249	
250			rec := BackupRecord{
251				Filename:  e.Name(),
252				FilePath:  fullPath,
253				SizeBytes: info.Size(),
254				CreatedAt: info.ModTime(),
255				Encrypted: true,
256			}
257	
258			// Try to load manifest for richer metadata.
259			manifestPath := strings.TrimSuffix(fullPath, ".sql.enc") + ".manifest.json"
260			if manifestBytes, err := os.ReadFile(manifestPath); err == nil {
261				var m BackupManifest
262				if err := json.Unmarshal(manifestBytes, &m); err == nil {
263					rec.CreatedAt = m.CreatedAt
264					rec.Encrypted = m.Encrypted
265					rec.ManifestPath = manifestPath
266				}
267			}
268	
269			records = append(records, rec)
270		}
271		return records, nil
272	}
273	
274	// ApplyRetention deletes backup files (and their manifests) older than
275	// cfg.Backup.RetentionDays days.
276	func (s *Service) ApplyRetention() error {
277		cutoff := time.Now().UTC().AddDate(0, 0, -s.cfg.Backup.RetentionDays)
278	
279		records, err := s.ListBackups()
280		if err != nil {
281			return err
282		}
283	
284		var lastErr error
285		for _, rec := range records {
286			if rec.CreatedAt.Before(cutoff) {
287				if err := os.Remove(rec.FilePath); err != nil && !os.IsNotExist(err) {
288					log.Printf("WARN backup retention: failed to remove %s: %v", rec.FilePath, err)
289					lastErr = err
290					continue
291				}
292				if rec.ManifestPath != "" {
293					if err := os.Remove(rec.ManifestPath); err != nil && !os.IsNotExist(err) {
294						log.Printf("WARN backup retention: failed to remove manifest %s: %v", rec.ManifestPath, err)
295					}
296				}
297				log.Printf("INFO backup retention: removed %s (created %s)", rec.Filename, rec.CreatedAt.Format(time.RFC3339))
298			}
299		}
300		return lastErr
301	}
