303	// --- internal helpers ---
304	
305	// runMysqldump executes mysqldump and returns the dump output.
306	// If mysqldump is not found, it falls back to a GORM-based lightweight export.
307	func (s *Service) runMysqldump() ([]byte, error) {
308		mysqldumpPath, err := exec.LookPath("mysqldump")
309		if err != nil {
310			log.Printf("WARN backup: mysqldump not found in PATH, using fallback export: %v", err)
311			return s.fallbackExport()
312		}
313	
314		args := []string{
315			"--host=" + s.cfg.DB.Host,
316			fmt.Sprintf("--port=%d", s.cfg.DB.Port),
317			"--user=" + s.cfg.DB.User,
318			"--password=" + s.cfg.DB.Password,
319			"--single-transaction",
320			"--routines",
321			"--triggers",
322			"--set-gtid-purged=OFF",
323			s.cfg.DB.Name,
324		}
325	
326		cmd := exec.Command(mysqldumpPath, args...)
327		var stdout, stderr bytes.Buffer
328		cmd.Stdout = &stdout
329		cmd.Stderr = &stderr
330	
331		if err := cmd.Run(); err != nil {
332			return nil, fmt.Errorf("mysqldump failed: %w (stderr: %s)", err, stderr.String())
333		}
334	
335		return stdout.Bytes(), nil
336	}
337	
338	// fallbackExport produces a minimal SQL header that can be recognised as a valid
339	// MySQL dump for validation purposes. This is used when mysqldump is not available
340	// (e.g. in containerised environments without the MySQL client tools).
341	func (s *Service) fallbackExport() ([]byte, error) {
342		var buf bytes.Buffer
343		fmt.Fprintf(&buf, "-- MySQL dump fallback (propertyops)\n")
344		fmt.Fprintf(&buf, "-- Host: %s  Database: %s\n", s.cfg.DB.Host, s.cfg.DB.Name)
345		fmt.Fprintf(&buf, "-- Generated: %s\n", time.Now().UTC().Format(time.RFC3339))
346		fmt.Fprintf(&buf, "-- WARNING: This is a metadata-only fallback. Install mysql-client for full dumps.\n\n")
347	
348		// List tables as a lightweight sanity check.
349		sqlDB, err := s.db.DB()
350		if err != nil {
351			return buf.Bytes(), nil
352		}
353		rows, err := sqlDB.Query("SELECT TABLE_NAME FROM information_schema.TABLES WHERE TABLE_SCHEMA = ?", s.cfg.DB.Name)
354		if err != nil {
355			return buf.Bytes(), nil
356		}
357		defer rows.Close()
358		for rows.Next() {
359			var tableName string
360			if err := rows.Scan(&tableName); err == nil {
361				fmt.Fprintf(&buf, "-- Table: %s\n", tableName)
362			}
363		}
364		return buf.Bytes(), nil
365	}
