59	// --- Notification sending ---
60	
61	// SendDirect creates a new notification with Pending status for direct delivery.
62	func (s *Service) SendDirect(recipientID uint64, subject, body, category string) (*Notification, *common.AppError) {
63		if subject == "" {
64			return nil, common.NewValidationError("subject is required")
65		}
66		if body == "" {
67			return nil, common.NewValidationError("body is required")
68		}
69		if category == "" {
70			category = "System"
71		}
72	
73		n := &Notification{
74			UUID:        uuid.New().String(),
75			RecipientID: recipientID,
76			Subject:     subject,
77			Body:        body,
78			Category:    category,
79			Status:      common.NotificationStatusPending,
80		}
81	
82		if err := s.repo.CreateNotification(n); err != nil {
83			return nil, common.NewInternalError("failed to create notification")
84		}
85	
86		return n, nil
87	}
