89	// SendFromTemplate looks up a notification template by name, renders the subject and body
90	// using the provided data map, and creates a pending notification.
91	func (s *Service) SendFromTemplate(templateName string, recipientID uint64, data map[string]string) (*Notification, *common.AppError) {
92		tmpl, err := s.repo.FindTemplateByName(templateName)
93		if err != nil {
94			if err == gorm.ErrRecordNotFound {
95				return nil, common.NewNotFoundError("Notification template")
96			}
97			return nil, common.NewInternalError("failed to look up template")
98		}
99	
100		subject, appErr := renderTemplate("subject", tmpl.SubjectTemplate, data)
101		if appErr != nil {
102			return nil, appErr
103		}
104	
105		body, appErr := renderTemplate("body", tmpl.BodyTemplate, data)
106		if appErr != nil {
107			return nil, appErr
108		}
109	
110		n := &Notification{
111			UUID:        uuid.New().String(),
112			RecipientID: recipientID,
113			TemplateID:  &tmpl.ID,
114			Subject:     subject,
115			Body:        body,
116			Category:    tmpl.Category,
117			Status:      common.NotificationStatusPending,
118		}
119	
120		if err := s.repo.CreateNotification(n); err != nil {
121			return nil, common.NewInternalError("failed to create notification from template")
122		}
123	
124		return n, nil
125	}
126	
127	// SendEvent is a convenience method for event-triggered notifications.
128	// It wraps SendFromTemplate and satisfies the NotificationSender interface
129	// expected by the workorders package.
130	func (s *Service) SendEvent(eventName string, recipientID uint64, data map[string]string) error {
131		_, appErr := s.SendFromTemplate(eventName, recipientID, data)
132		if appErr != nil {
133			return fmt.Errorf("%s", appErr.Message)
134		}
135		return nil
136	}
137	
138	// SendEventToRole sends an event-triggered notification to all active users with the given role.
139	// Errors from individual sends are logged but do not abort the fan-out.
140	func (s *Service) SendEventToRole(eventName, role string, data map[string]string) error {
141		ids, err := s.repo.FindUserIDsByRole(role)
142		if err != nil {
143			return fmt.Errorf("SendEventToRole: failed to resolve recipients for role %q: %w", role, err)
144		}
145		for _, id := range ids {
146			if _, appErr := s.SendFromTemplate(eventName, id, data); appErr != nil {
147				// Best-effort: log individual failures but continue fan-out.
148				_ = appErr
149			}
150		}
151		return nil
152	}
