221	func (s *Service) GetUnreadCount(userID uint64) (int64, *common.AppError) {
222		count, err := s.repo.CountUnread(userID)
223		if err != nil {
224			return 0, common.NewInternalError("failed to count unread notifications")
225		}
226		return count, nil
