229	// GetByID retrieves a notification by ID, enforcing that it belongs to the requesting user.
230	func (s *Service) GetByID(notificationID, userID uint64) (*Notification, bool, *common.AppError) {
231		n, err := s.repo.FindByID(notificationID)
232		if err != nil {
233			if err == gorm.ErrRecordNotFound {
234				return nil, false, common.NewNotFoundError("Notification")
235			}
236			return nil, false, common.NewInternalError("failed to find notification")
237		}
238	
239		if n.RecipientID != userID {
240			return nil, false, common.NewForbiddenError("you can only view your own notifications")
241		}
242	
243		// Check if read.
244		receipt, _ := s.repo.FindReceipt(notificationID, userID)
245		isRead := receipt != nil
246	
247		return n, isRead, nil
248	}
