280	// CreateThread creates a new message thread and adds the creator as a participant.
281	func (s *Service) CreateThread(creatorID uint64, req CreateThreadRequest) (*MessageThread, *common.AppError) {
282		if req.Subject == "" {
283			return nil, common.NewValidationError("subject is required")
284		}
285	
286		thread := &MessageThread{
287			UUID:        uuid.New().String(),
288			WorkOrderID: req.WorkOrderID,
289			Subject:     req.Subject,
290			CreatedBy:   creatorID,
291		}
292	
293		if err := s.repo.CreateThread(thread); err != nil {
294			return nil, common.NewInternalError("failed to create thread")
295		}
296	
297		// Add creator as participant.
298		participant := &ThreadParticipant{
299			ThreadID: thread.ID,
300			UserID:   creatorID,
301			JoinedAt: time.Now().UTC(),
302		}
303		if err := s.repo.AddParticipant(participant); err != nil {
304			return nil, common.NewInternalError("failed to add thread participant")
305		}
306	
307		return thread, nil
308	}
