1	package notifications
2	
3	import (
4		"time"
5	
6		"gorm.io/gorm"
7	)
8	
9	// Repository handles all notification and thread database operations.
10	type Repository struct {
11		db *gorm.DB
12	}
13	
14	// NewRepository creates a new notification Repository.
15	func NewRepository(db *gorm.DB) *Repository {
16		return &Repository{db: db}
17	}
18	
19	// --- Notification operations ---
20	
21	// CreateNotification inserts a new notification record.
22	func (r *Repository) CreateNotification(n *Notification) error {
23		return r.db.Create(n).Error
24	}
25	
26	// FindByID loads a notification by its primary key.
27	func (r *Repository) FindByID(id uint64) (*Notification, error) {
28		var n Notification
29		err := r.db.Where("id = ?", id).First(&n).Error
30		if err != nil {
31			return nil, err
32		}
33		return &n, nil
34	}
35	
36	// NotificationFilters holds optional filters for listing notifications.
37	type NotificationFilters struct {
38		Status   string
39		Category string
40		ReadFlag string // "true", "false", or "" (all)
41		UserID   uint64
42	}
43	
44	// FindByRecipient retrieves notifications for a user with filtering and pagination.
45	func (r *Repository) FindByRecipient(userID uint64, filters NotificationFilters, offset, limit int) ([]Notification, int64, error) {
46		query := r.db.Model(&Notification{}).Where("recipient_id = ?", userID)
47	
48		if filters.Status != "" {
49			query = query.Where("status = ?", filters.Status)
50		}
51		if filters.Category != "" {
52			query = query.Where("category = ?", filters.Category)
53		}
54		if filters.ReadFlag == "true" {
55			query = query.Where("id IN (SELECT notification_id FROM notification_receipts WHERE user_id = ?)", userID)
56		} else if filters.ReadFlag == "false" {
57			query = query.Where("id NOT IN (SELECT notification_id FROM notification_receipts WHERE user_id = ?)", userID)
58		}
59	
60		var total int64
61		if err := query.Count(&total).Error; err != nil {
62			return nil, 0, err
63		}
64	
65		var notifications []Notification
66		err := query.Order("created_at DESC").Offset(offset).Limit(limit).Find(&notifications).Error
67		if err != nil {
68			return nil, 0, err
69		}
70	
71		return notifications, total, nil
72	}
73	
74	// CountUnread returns the number of unread notifications for a user.
75	func (r *Repository) CountUnread(userID uint64) (int64, error) {
76		var count int64
77		err := r.db.Model(&Notification{}).
78			Where("recipient_id = ?", userID).
79			Where("id NOT IN (SELECT notification_id FROM notification_receipts WHERE user_id = ?)", userID).
80			Count(&count).Error
81		return count, err
82	}
83	
84	// UpdateNotificationStatus updates the status of a notification and optionally sets SentAt.
85	func (r *Repository) UpdateNotificationStatus(id uint64, status string) error {
86		updates := map[string]interface{}{
87			"status": status,
88		}
89		if status == "Sent" {
90			now := time.Now().UTC()
91			updates["sent_at"] = &now
92		}
93		return r.db.Model(&Notification{}).Where("id = ?", id).Updates(updates).Error
94	}
95	
96	// FindPendingNotifications retrieves notifications that are pending and due to be sent.
97	func (r *Repository) FindPendingNotifications(limit int) ([]Notification, error) {
98		var notifications []Notification
99		now := time.Now().UTC()
100		err := r.db.Where("status = ? AND (scheduled_for IS NULL OR scheduled_for <= ?)", "Pending", now).
101			Order("created_at ASC").
102			Limit(limit).
103			Find(&notifications).Error
104		return notifications, err
105	}
106	
107	// IncrementRetry increments the retry count and sets the last retry timestamp.
108	func (r *Repository) IncrementRetry(id uint64) error {
109		now := time.Now().UTC()
110		return r.db.Model(&Notification{}).Where("id = ?", id).
111			Updates(map[string]interface{}{
112				"retry_count":  gorm.Expr("retry_count + 1"),
113				"last_retry_at": &now,
114			}).Error
115	}
116	
117	// FindUserIDsByRole returns IDs of all active users with the given role name.
118	func (r *Repository) FindUserIDsByRole(role string) ([]uint64, error) {
119		var ids []uint64
120		err := r.db.Raw(`SELECT u.id FROM users u
121			JOIN user_roles ur ON ur.user_id = u.id
122			JOIN roles ro ON ro.id = ur.role_id
123			WHERE ro.name = ? AND u.is_active = ?`, role, true).Scan(&ids).Error
124		return ids, err
125	}
