129	// CreateReceipt inserts a new notification receipt.
130	func (r *Repository) CreateReceipt(receipt *NotificationReceipt) error {
131		return r.db.Create(receipt).Error
132	}
133	
134	// FindReceipt looks up a receipt for a specific notification and user.
135	func (r *Repository) FindReceipt(notificationID, userID uint64) (*NotificationReceipt, error) {
136		var receipt NotificationReceipt
137		err := r.db.Where("notification_id = ? AND user_id = ?", notificationID, userID).First(&receipt).Error
138		if err != nil {
139			return nil, err
140		}
