146	// FindTemplateByName loads a notification template by its unique name.
147	func (r *Repository) FindTemplateByName(name string) (*NotificationTemplate, error) {
148		var tmpl NotificationTemplate
149		err := r.db.Where("name = ? AND is_active = ?", name, true).First(&tmpl).Error
