53		ReportCategoryMaintenance = "Maintenance"
54		ReportCategoryFraud       = "Fraud"
55		ReportCategoryOther       = "Other"
56	)
57	
58	var validReportCategories = map[string]bool{
59		ReportCategoryHarassment:  true,
60		ReportCategoryDamage:      true,
61		ReportCategoryNoise:       true,
62		ReportCategoryMaintenance: true,
63		ReportCategoryFraud:       true,
