228	// --- Enforcement operations ---
229	
230	// ApplyEnforcement creates an enforcement action against a user.
231	func (s *Service) ApplyEnforcement(req CreateEnforcementRequest, actorID uint64, ip, requestID string) (*EnforcementAction, *common.AppError) {
232		// Validate action type.
233		switch req.ActionType {
234		case common.EnforcementWarning, common.EnforcementRateLimit, common.EnforcementSuspension:
235			// valid
236		default:
237			return nil, common.NewValidationError("action_type must be Warning, RateLimit, or Suspension")
238		}
239	
240		// Validate reason.
241		if fe := common.ValidateStringLength("reason", req.Reason, 10, 2000); fe != nil {
242			return nil, common.NewValidationError("Validation failed", *fe)
243		}
244	
245		// For rate limit, require the rate limit fields.
246		if req.ActionType == common.EnforcementRateLimit {
247			if req.RateLimitMax == nil || *req.RateLimitMax <= 0 {
248				return nil, common.NewFieldValidationError("rate_limit_max", "must be greater than 0 for RateLimit actions")
249			}
250			if req.RateLimitWindowMinutes == nil || *req.RateLimitWindowMinutes <= 0 {
251				return nil, common.NewFieldValidationError("rate_limit_window_minutes", "must be greater than 0 for RateLimit actions")
252			}
253		}
254	
255		now := time.Now().UTC()
256		action := &EnforcementAction{
257			UUID:       uuid.New().String(),
258			UserID:     req.UserID,
259			ReportID:   req.ReportID,
260			ActionType: req.ActionType,
261			Reason:     req.Reason,
262			StartsAt:   now,
263			IsActive:   true,
264			CreatedBy:  actorID,
265		}
266	
267		// Calculate ends_at for suspensions.
268		if req.ActionType == common.EnforcementSuspension {
269			switch req.EndsAt {
270			case "1day":
271				endsAt := now.Add(24 * time.Hour)
272				action.EndsAt = &endsAt
273			case "7day":
274				endsAt := now.Add(7 * 24 * time.Hour)
275				action.EndsAt = &endsAt
276			case "indefinite", "":
277				// nil ends_at = indefinite suspension
278				action.EndsAt = nil
279			default:
280				return nil, common.NewFieldValidationError("ends_at", "must be 1day, 7day, or indefinite")
281			}
282		}
283	
284		// Set rate limit fields.
285		if req.ActionType == common.EnforcementRateLimit {
286			action.RateLimitMax = req.RateLimitMax
287			action.RateLimitWindowMinutes = req.RateLimitWindowMinutes
288		}
289	
290		if err := s.repo.CreateEnforcement(action); err != nil {
291			return nil, common.NewInternalError("failed to create enforcement action")
292		}
293	
294		// Audit log.
295		s.audit.Log(actorID, common.AuditActionEnforcement, "EnforcementAction", action.ID,
296			fmt.Sprintf("%s enforcement applied to user %d: %s", req.ActionType, req.UserID, req.Reason), ip, requestID)
297	
298		// Notify the target user.
299		if s.notifier != nil {
300			if err := s.notifier.SendEvent("enforcement_applied", req.UserID, map[string]string{
301				"action_type":    req.ActionType,
302				"enforcement_id": fmt.Sprintf("%d", action.ID),
303				"reason":         req.Reason,
304			}); err != nil {
305				log.Printf("WARN governance: notification send failed for enforcement_applied (action %d): %v", action.ID, err)
306			}
307		}
308	
309		return action, nil
310	}
311	
312	// RevokeEnforcement deactivates an enforcement action.
313	func (s *Service) RevokeEnforcement(enforcementID uint64, req RevokeEnforcementRequest, actorID uint64, ip, requestID string) (*EnforcementAction, *common.AppError) {
314		if fe := common.ValidateStringLength("reason", req.Reason, 10, 2000); fe != nil {
315			return nil, common.NewValidationError("Validation failed", *fe)
316		}
317	
318		action, err := s.repo.FindEnforcementByID(enforcementID)
319		if err != nil {
320			if err == gorm.ErrRecordNotFound {
321				return nil, common.NewNotFoundError("Enforcement action")
322			}
323			return nil, common.NewInternalError("failed to retrieve enforcement action")
324		}
325	
326		if !action.IsActive {
327			return nil, common.NewConflictError("enforcement action is already revoked")
328		}
329	
330		now := time.Now().UTC()
331		action.IsActive = false
332		action.RevokedAt = &now
333		action.RevokedBy = &actorID
334	
335		if err := s.repo.RevokeEnforcement(action); err != nil {
336			return nil, common.NewInternalError("failed to revoke enforcement action")
337		}
338	
339		s.audit.Log(actorID, common.AuditActionEnforcement, "EnforcementAction", action.ID,
340			fmt.Sprintf("Enforcement revoked for user %d: %s", action.UserID, req.Reason), ip, requestID)
341	
342		// Notify the user that their enforcement has been revoked.
343		if s.notifier != nil {
344			if err := s.notifier.SendEvent("enforcement_revoked", action.UserID, map[string]string{
345				"enforcement_id": fmt.Sprintf("%d", action.ID),
346				"action_type":    action.ActionType,
347			}); err != nil {
348				log.Printf("WARN governance: notification send failed for enforcement_revoked (action %d): %v", action.ID, err)
349			}
350		}
351	
352		return action, nil
353	}
