379	func (s *Service) CreateKeyword(req KeywordRequest, actorID uint64, ip, requestID string) (*KeywordBlacklist, *common.AppError) {
380		if fe := common.ValidateStringLength("keyword", req.Keyword, 2, 255); fe != nil {
