41	// CreateProfile creates a new tenant profile.
42	func (s *Service) CreateProfile(req CreateTenantProfileRequest, actorID uint64, ip, requestID string) (*TenantProfileResponse, *common.AppError) {
43		// Check if profile already exists for this user
44		if existing, _ := s.repo.FindByUserID(req.UserID); existing != nil {
45			return nil, common.NewConflictError("tenant profile already exists for this user")
46		}
47	
48		profile := &TenantProfile{
49			UUID:   uuid.New().String(),
50			UserID: req.UserID,
51			UnitID: req.UnitID,
52		}
53	
54		// Encrypt emergency contact if provided
55		if req.EmergencyContact != "" {
56			encrypted, keyVer, err := s.encryptor.Encrypt([]byte(req.EmergencyContact))
57			if err != nil {
58				return nil, common.NewInternalError("failed to encrypt emergency contact")
59			}
60			profile.EmergencyContactEncrypted = encrypted
61			profile.EmergencyContactKeyVersion = &keyVer
62		}
63	
64		// Parse dates
65		if req.LeaseStart != "" {
66			t, err := time.Parse("2006-01-02", req.LeaseStart)
67			if err != nil {
68				return nil, common.NewValidationError("Validation failed",
69					common.FieldError{Field: "lease_start", Message: "must be in YYYY-MM-DD format"})
70			}
71			profile.LeaseStart = &t
72		}
73		if req.LeaseEnd != "" {
74			t, err := time.Parse("2006-01-02", req.LeaseEnd)
75			if err != nil {
76				return nil, common.NewValidationError("Validation failed",
77					common.FieldError{Field: "lease_end", Message: "must be in YYYY-MM-DD format"})
78			}
79			profile.LeaseEnd = &t
80		}
81		if req.MoveInDate != "" {
82			t, err := time.Parse("2006-01-02", req.MoveInDate)
83			if err != nil {
84				return nil, common.NewValidationError("Validation failed",
85					common.FieldError{Field: "move_in_date", Message: "must be in YYYY-MM-DD format"})
86			}
87			profile.MoveInDate = &t
88		}
89		if req.Notes != "" {
90			profile.Notes = &req.Notes
91		}
92	
93		if err := s.repo.Create(profile); err != nil {
94			return nil, common.NewInternalError("failed to create tenant profile")
95		}
96	
97		s.audit.Log(actorID, common.AuditActionCreate, "TenantProfile", profile.ID,
98			fmt.Sprintf("Created tenant profile for user %d", req.UserID), ip, requestID)
