295	// LocalNetworkOnly restricts access to requests originating from the specified
296	// CIDR ranges. Returns 403 for requests from disallowed IPs.
297	func (m *Middleware) LocalNetworkOnly(allowedCIDRs []string) gin.HandlerFunc {
298		// Parse CIDRs at middleware creation time
299		nets := make([]*net.IPNet, 0, len(allowedCIDRs))
300		for _, cidr := range allowedCIDRs {
301			_, ipNet, err := net.ParseCIDR(cidr)
302			if err != nil {
303				log.Printf("WARN LocalNetworkOnly: invalid CIDR %q: %v", cidr, err)
304				continue
305			}
306			nets = append(nets, ipNet)
307		}
308	
309		return func(c *gin.Context) {
310			clientIP := net.ParseIP(c.ClientIP())
311			if clientIP == nil {
312				common.RespondError(c, common.NewForbiddenError("Unable to determine client IP"))
313				c.Abort()
314				return
315			}
316	
317			for _, ipNet := range nets {
318				if ipNet.Contains(clientIP) {
319					c.Next()
320					return
321				}
322			}
323	
324			common.RespondError(c, common.NewForbiddenError(fmt.Sprintf("Access restricted to local network")))
325			c.Abort()
326		}
327	}
