329	// AnomalyAllowlist checks client IP against configured CIDR allowlist.
330	// Uses the anomaly.AllowedCIDRs from the application configuration.
331	func (m *Middleware) AnomalyAllowlist() gin.HandlerFunc {
332		return m.LocalNetworkOnly(m.cfg.Anomaly.AllowedCIDRs)
333	}
