335	// CORS returns a middleware that sets Cross-Origin Resource Sharing headers.
336	func (m *Middleware) CORS(allowedOrigins []string) gin.HandlerFunc {
337		originsMap := make(map[string]struct{}, len(allowedOrigins))
338		for _, o := range allowedOrigins {
339			originsMap[o] = struct{}{}
340		}
341	
342		return func(c *gin.Context) {
343			origin := c.GetHeader("Origin")
344			if _, ok := originsMap[origin]; ok {
345				c.Header("Access-Control-Allow-Origin", origin)
346			}
347			c.Header("Access-Control-Allow-Methods", "GET, POST, PUT, PATCH, DELETE, OPTIONS")
348			c.Header("Access-Control-Allow-Headers", "Authorization, Content-Type, X-Request-ID")
349			c.Header("Access-Control-Max-Age", "86400")

