5	// PropertyQuerier abstracts the property-related queries needed by the dispatch service.
6	type PropertyQuerier interface {
7		FindTechniciansByPropertyAndSkill(propertyID uint64, skillTag string) ([]uint64, error)
8		GetDispatchCursor(propertyID uint64, skillTag string) (int, error)
9		UpdateDispatchCursor(propertyID uint64, skillTag string, position int, userID uint64) error
10	}
11	
12	// DispatchService handles deterministic round-robin dispatch of work orders
13	// to technicians based on property and skill tag.
14	type DispatchService struct {
15		propQuerier PropertyQuerier
16	}
17	
18	// NewDispatchService creates a new DispatchService.
19	func NewDispatchService(pq PropertyQuerier) *DispatchService {
20		return &DispatchService{propQuerier: pq}
21	}
22	
23	// DispatchResult holds the result of a dispatch attempt.
24	type DispatchResult struct {
25		TechnicianID uint64
26		Assigned     bool
27		Message      string
28	}
29	
30	// Dispatch selects the next technician using round-robin for the given property and skill tag.
31	// It returns the selected technician ID and whether assignment was successful.
32	// If no technicians are available, Assigned is false and Message explains why.
33	func (d *DispatchService) Dispatch(propertyID uint64, skillTag string) (*DispatchResult, error) {
34		// Get eligible technicians sorted by ID for deterministic ordering.
35		techs, err := d.propQuerier.FindTechniciansByPropertyAndSkill(propertyID, skillTag)
36		if err != nil {
37			return nil, fmt.Errorf("failed to find technicians: %w", err)
38		}
39	
40		if len(techs) == 0 {
41			return &DispatchResult{
42				Assigned: false,
43				Message:  "no technicians available for the requested property and skill",
44			}, nil
45		}
46	
47		// Get the current cursor position.
48		cursor, err := d.propQuerier.GetDispatchCursor(propertyID, skillTag)
49		if err != nil {
50			return nil, fmt.Errorf("failed to get dispatch cursor: %w", err)
51		}
52	
53		// Select next technician using modulo wrap-around.
54		idx := cursor % len(techs)
55		selectedTech := techs[idx]
56	
57		// Advance cursor to next position.
58		nextCursor := cursor + 1
59		if err := d.propQuerier.UpdateDispatchCursor(propertyID, skillTag, nextCursor, selectedTech); err != nil {
60			return nil, fmt.Errorf("failed to update dispatch cursor: %w", err)
61		}
62	
63		return &DispatchResult{
64			TechnicianID: selectedTech,
65			Assigned:     true,
66			Message:      fmt.Sprintf("assigned to technician %d", selectedTech),
67		}, nil
68	}
