// (e.g. in containerised environments without the MySQL client tools).
func (s *Service) fallbackExport() ([]byte, error) {
	var buf bytes.Buffer
	fmt.Fprintf(&buf, "-- MySQL dump fallback (propertyops)\n")
	fmt.Fprintf(&buf, "-- Host: %s  Database: %s\n", s.cfg.DB.Host, s.cfg.DB.Name)
	fmt.Fprintf(&buf, "-- Generated: %s\n", time.Now().UTC().Format(time.RFC3339))
	fmt.Fprintf(&buf, "-- WARNING: This is a metadata-only fallback. Install mysql-client for full dumps.\n\n")

	// List tables as a lightweight sanity check.
	sqlDB, err := s.db.DB()
	if err != nil {
		return buf.Bytes(), nil
	}
	rows, err := sqlDB.Query("SELECT TABLE_NAME FROM information_schema.TABLES WHERE TABLE_SCHEMA = ?", s.cfg.DB.Name)
	if err != nil {
		return buf.Bytes(), nil
	}
	defer rows.Close()
	for rows.Next() {
		var tableName string
		if err := rows.Scan(&tableName); err == nil {
			fmt.Fprintf(&buf, "-- Table: %s\n", tableName)
		}
	}
	return buf.Bytes(), nil
}

