229	func envStrSlice(key string, fallback []string) []string {
230		if v := os.Getenv(key); v != "" {
231			parts := strings.Split(v, ",")
232			result := make([]string, 0, len(parts))
233			for _, p := range parts {
234				if t := strings.TrimSpace(p); t != "" {
235					result = append(result, t)
236				}
237			}
