111	// SendFromTemplate looks up a notification template by name, renders the subject and body
112	// using the provided data map, and creates a pending notification.
113	func (s *Service) SendFromTemplate(templateName string, recipientID uint64, data map[string]string) (*Notification, *common.AppError) {
114		tmpl, err := s.repo.FindTemplateByName(templateName)
115		if err != nil {
116			if err == gorm.ErrRecordNotFound {
117				return nil, common.NewNotFoundError("Notification template")
118			}
119			return nil, common.NewInternalError("failed to look up template")
120		}
121	
122		subject, appErr := renderTemplate("subject", tmpl.SubjectTemplate, data)
123		if appErr != nil {
124			return nil, appErr
125		}
126	
127		body, appErr := renderTemplate("body", tmpl.BodyTemplate, data)
128		if appErr != nil {
129			return nil, appErr
130		}
131	
132		n := &Notification{
133			UUID:        uuid.New().String(),
134			RecipientID: recipientID,
135			TemplateID:  &tmpl.ID,
136			Subject:     subject,
137			Body:        body,
138			Category:    tmpl.Category,
139			Status:      common.NotificationStatusPending,
140		}
141	
142		if err := s.repo.CreateNotification(n); err != nil {
143			return nil, common.NewInternalError("failed to create notification from template")
144		}
145	
146		return n, nil
147	}
