51	// PaymentFilters holds optional filters for listing payments.
52	type PaymentFilters struct {
53		PropertyID          *uint64
54		PropertyIDs         []uint64
55		ScopedToPropertyIDs bool // when true, PropertyIDs is an authoritative allow-list (empty = no results)
56		Status              string
57		Kind                string
58		TenantID            *uint64
59	}
60	
61	// List retrieves payments matching the given filters with pagination.
62	func (r *Repository) List(filters PaymentFilters, offset, limit int) ([]Payment, int64, error) {
63		query := r.db.Model(&Payment{})
64	
65		if filters.PropertyID != nil {
66			query = query.Where("property_id = ?", *filters.PropertyID)
67		} else if filters.ScopedToPropertyIDs {
68			if len(filters.PropertyIDs) == 0 {
69				// PM has no managed properties — return zero results.
70				return nil, 0, nil
71			}
72			query = query.Where("property_id IN ?", filters.PropertyIDs)
73		}
74		if filters.Status != "" {
75			query = query.Where("status = ?", filters.Status)
76		}
77		if filters.Kind != "" {
78			query = query.Where("kind = ?", filters.Kind)
79		}
80		if filters.TenantID != nil {
81			query = query.Where("tenant_id = ?", *filters.TenantID)
82		}
83	
84		var total int64
85		if err := query.Count(&total).Error; err != nil {
86			return nil, 0, err
87		}
88	
89		var payments []Payment
90		err := query.Order("created_at DESC").Offset(offset).Limit(limit).Find(&payments).Error
91		if err != nil {
92			return nil, 0, err
93		}
94	
95		return payments, total, nil
96	}
