98	// FindExpiredIntents finds all pending intents whose expires_at has passed.
99	func (r *Repository) FindExpiredIntents() ([]Payment, error) {
100		var payments []Payment
101		now := time.Now().UTC()
102		err := r.db.Where("kind = ? AND status = ? AND expires_at IS NOT NULL AND expires_at <= ?",
103			"Intent", "Pending", now).
104			Find(&payments).Error
105		return payments, err
106	}
107	
108	// FindByDateAndKinds retrieves all payments for a given date and set of kinds.
109	func (r *Repository) FindByDateAndKinds(date time.Time, kinds []string) ([]Payment, error) {
110		startOfDay := time.Date(date.Year(), date.Month(), date.Day(), 0, 0, 0, 0, time.UTC)
111		endOfDay := startOfDay.Add(24 * time.Hour)
112	
113		var payments []Payment
114		err := r.db.Where("kind IN ? AND status IN ? AND created_at >= ? AND created_at < ?",
115			kinds, []string{"Paid", "Settled"}, startOfDay, endOfDay).
116			Find(&payments).Error
117		return payments, err
118	}
