1	package security
2	
3	import (
4		"crypto/aes"
5		"crypto/cipher"
6		"crypto/rand"
7		"encoding/binary"
8		"fmt"
9		"io"
10		"os"
11		"path/filepath"
12		"sort"
13		"strconv"
14		"strings"
15		"sync"
16		"time"
17	
18		"propertyops/backend/internal/config"
19	)
20	
21	// Service provides field-level encryption and key management.
22	type Service struct {
23		mu       sync.RWMutex
24		keys     map[int][]byte // keyVersion -> 32-byte AES-256 key
25		activeID int
26		cfg      config.EncryptionConfig
27	}
28	
29	// NewService initialises the security service by loading keys from cfg.KeyDir.
30	func NewService(cfg config.EncryptionConfig) *Service {
31		s := &Service{
32			keys:     make(map[int][]byte),
33			activeID: cfg.ActiveKeyID,
34			cfg:      cfg,
35		}
36		if err := s.loadKeys(); err != nil {
37			// Non-fatal: log and continue; callers will fail on encrypt/decrypt.
38			fmt.Fprintf(os.Stderr, "security: failed to load keys from %s: %v\n", cfg.KeyDir, err)
39		}
40		return s
41	}
42	
43	// loadKeys reads key files named <version>.key from the key directory.
44	// Each file must contain exactly 32 bytes (AES-256).
45	func (s *Service) loadKeys() error {
46		entries, err := os.ReadDir(s.cfg.KeyDir)
47		if err != nil {
48			if os.IsNotExist(err) {
49				// Auto-generate a key if directory doesn't exist yet.
50				_ = os.MkdirAll(s.cfg.KeyDir, 0700)
51				return s.generateKey(s.cfg.ActiveKeyID)
52			}
53			return err
54		}
55	
56		loaded := 0
57		for _, e := range entries {
58			if e.IsDir() {
59				continue
60			}
61			name := e.Name()
62			if !strings.HasSuffix(name, ".key") {
63				continue
64			}
65			versionStr := strings.TrimSuffix(name, ".key")
66			version, err := strconv.Atoi(versionStr)
67			if err != nil {
68				continue
69			}
70			keyBytes, err := os.ReadFile(filepath.Join(s.cfg.KeyDir, name))
71			if err != nil {
72				continue
73			}
74			if len(keyBytes) != 32 {
75				continue
76			}
77			s.keys[version] = keyBytes
78			loaded++
79		}
80	
81		if loaded == 0 {
82			return s.generateKey(s.cfg.ActiveKeyID)
83		}
84		return nil
85	}
86	
87	// generateKey creates a new random 32-byte key and writes it to disk.
88	func (s *Service) generateKey(version int) error {
89		key := make([]byte, 32)
90		if _, err := io.ReadFull(rand.Reader, key); err != nil {
91			return err
92		}
93		path := filepath.Join(s.cfg.KeyDir, fmt.Sprintf("%d.key", version))
94		if err := os.WriteFile(path, key, 0600); err != nil {
95			return err
96		}
97		s.keys[version] = key
98		return nil
99	}
100	
101	// Encrypt encrypts plaintext using AES-256-GCM with the active key.
102	// The returned ciphertext is: [4-byte big-endian keyVersion][12-byte nonce][GCM ciphertext+tag].
103	func (s *Service) Encrypt(plaintext []byte) ([]byte, int, error) {
104		s.mu.RLock()
105		key, ok := s.keys[s.activeID]
106		keyVersion := s.activeID
107		s.mu.RUnlock()
108	
109		if !ok {
110			return nil, 0, fmt.Errorf("security: active key %d not loaded", s.activeID)
111		}
112	
113		block, err := aes.NewCipher(key)
114		if err != nil {
115			return nil, 0, err
116		}
117		gcm, err := cipher.NewGCM(block)
118		if err != nil {
119			return nil, 0, err
120		}
121	
122		nonce := make([]byte, gcm.NonceSize())
123		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
124			return nil, 0, err
125		}
126	
127		ciphertext := gcm.Seal(nil, nonce, plaintext, nil)
128	
129		// Prepend 4-byte key version and nonce so Decrypt can unwrap.
130		out := make([]byte, 4+len(nonce)+len(ciphertext))
131		binary.BigEndian.PutUint32(out[0:4], uint32(keyVersion))
132		copy(out[4:4+len(nonce)], nonce)
133		copy(out[4+len(nonce):], ciphertext)
134	
135		return out, keyVersion, nil
136	}
137	
138	// Decrypt decrypts a ciphertext blob previously produced by Encrypt.
139	// keyVersion is used as a cross-check against the embedded version.
140	func (s *Service) Decrypt(ciphertext []byte, keyVersion int) ([]byte, error) {
141		if len(ciphertext) < 4 {
142			return nil, fmt.Errorf("security: ciphertext too short")
143		}
144	
145		embeddedVersion := int(binary.BigEndian.Uint32(ciphertext[0:4]))
146		if embeddedVersion != keyVersion {
147			return nil, fmt.Errorf("security: key version mismatch: got %d, want %d", embeddedVersion, keyVersion)
148		}
149	
150		s.mu.RLock()
151		key, ok := s.keys[keyVersion]
152		s.mu.RUnlock()
153		if !ok {
154			return nil, fmt.Errorf("security: key version %d not found", keyVersion)
155		}
156	
157		block, err := aes.NewCipher(key)
158		if err != nil {
159			return nil, err
160		}
161		gcm, err := cipher.NewGCM(block)
162		if err != nil {
163			return nil, err
164		}
165	
166		nonceSize := gcm.NonceSize()
167		if len(ciphertext) < 4+nonceSize {
168			return nil, fmt.Errorf("security: ciphertext too short for nonce")
169		}
170	
171		nonce := ciphertext[4 : 4+nonceSize]
172		ct := ciphertext[4+nonceSize:]
173	
174		plaintext, err := gcm.Open(nil, nonce, ct, nil)
175		if err != nil {
176			return nil, fmt.Errorf("security: decryption failed: %w", err)
177		}
178		return plaintext, nil
179	}
180	
181	// ActiveKeyID returns the ID of the currently active encryption key.
182	func (s *Service) ActiveKeyID() int {
183		s.mu.RLock()
184		defer s.mu.RUnlock()
185		return s.activeID
186	}
187	
188	// KeyRotationDue reports whether a new key should be generated based on RotationDays.
189	// It checks the modification time of the active key file.
190	func (s *Service) KeyRotationDue() bool {
191		path := filepath.Join(s.cfg.KeyDir, fmt.Sprintf("%d.key", s.activeID))
192		info, err := os.Stat(path)
193		if err != nil {
194			return true
195		}
196		return time.Since(info.ModTime()) > time.Duration(s.cfg.RotationDays)*24*time.Hour
197	}
198	
199	// ListKeyVersions returns the sorted list of loaded key versions.
200	func (s *Service) ListKeyVersions() ([]int, error) {
201		s.mu.RLock()
202		defer s.mu.RUnlock()
203		versions := make([]int, 0, len(s.keys))
204		for v := range s.keys {
205			versions = append(versions, v)
206		}
207		sort.Ints(versions)
208		return versions, nil
209	}
210	
211	// RotateKey generates a new key with version = current max + 1, sets it as active,
212	// persists it to disk, and returns the new version.
213	func (s *Service) RotateKey() (int, error) {
214		s.mu.Lock()
215		defer s.mu.Unlock()
216	
217		newVersion := s.activeID + 1
218		for v := range s.keys {
219			if v >= newVersion {
220				newVersion = v + 1
221			}
222		}
223	
224		if err := s.generateKey(newVersion); err != nil {
225			return 0, fmt.Errorf("security: failed to generate new key: %w", err)
226		}
227		s.activeID = newVersion
228		return newVersion, nil
229	}
