23	// testConfig returns a minimal Config suitable for integration tests.
24	// It does not require any real DB, encryption keys, or storage paths.
25	func testConfig() *config.Config {
26		return &config.Config{
27			Server: config.ServerConfig{Port: 0, GinMode: "test"},
28			DB:     config.DBConfig{},
29			Auth: config.AuthConfig{
30				BcryptCost:         4, // minimum cost for fast tests
31				SessionIdleTimeout: 30 * time.Minute,
