61	// newTestRouter builds a full Gin engine backed by the provided SQLite DB.
62	// All routes and middleware are registered exactly as in production via app.RegisterRoutes.
63	func newTestRouter(db *gorm.DB, cfg *config.Config) *gin.Engine {
