69	// makeRequest performs an HTTP request against the provided router and returns the recorder.
70	// token is the raw bearer token; pass "" to omit the Authorization header.
71	// body may be nil for requests without a body.
72	func makeRequest(t *testing.T, router *gin.Engine, method, path, token string, body interface{}) *httptest.ResponseRecorder {
73		t.Helper()
74	
75		var reqBody *bytes.Buffer
76		if body != nil {
77			data, err := json.Marshal(body)
78			if err != nil {
79				t.Fatalf("makeRequest: marshal body: %v", err)
80			}
81			reqBody = bytes.NewBuffer(data)
82		} else {
83			reqBody = bytes.NewBuffer(nil)
84		}
85	
86		req, err := http.NewRequest(method, path, reqBody)
87		if err != nil {
88			t.Fatalf("makeRequest: new request: %v", err)
89		}
90	
91		if body != nil {
92			req.Header.Set("Content-Type", "application/json")
93		}
94		if token != "" {
95			req.Header.Set("Authorization", "Bearer "+token)
96		}
97	
98		w := httptest.NewRecorder()
99		router.ServeHTTP(w, req)
100		return w
101	}
102	
103	// makeRawRequest performs an HTTP request with a pre-encoded JSON string body.
104	func makeRawRequest(t *testing.T, router *gin.Engine, method, path, token, rawBody string) *httptest.ResponseRecorder {
105		t.Helper()
106	
107		var bodyReader *strings.Reader
108		if rawBody != "" {
109			bodyReader = strings.NewReader(rawBody)
110		} else {
111			bodyReader = strings.NewReader("")
112		}
113	
114		req, err := http.NewRequest(method, path, bodyReader)
115		if err != nil {
116			t.Fatalf("makeRawRequest: %v", err)
117		}
118		if rawBody != "" {
119			req.Header.Set("Content-Type", "application/json")
120		}
121		if token != "" {
122			req.Header.Set("Authorization", "Bearer "+token)
123		}
124	
125		w := httptest.NewRecorder()
126		router.ServeHTTP(w, req)
127		return w
128	}
