130	// loginUser logs in a user via the API and returns the raw bearer token.
131	// Fails the test if the login does not return 200 or does not include a token.
132	func loginUser(t *testing.T, router *gin.Engine, username, password string) string {
133		t.Helper()
134	
135		w := makeRequest(t, router, http.MethodPost, "/api/v1/auth/login", "", map[string]string{
136			"username": username,
137			"password": password,
138		})
139	
140		if w.Code != http.StatusOK {
141			t.Fatalf("loginUser: expected 200, got %d; body: %s", w.Code, w.Body.String())
142		}
143	
144		var resp struct {
145			Data struct {
146				Token string `json:"token"`
147			} `json:"data"`
148		}
149		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
150			t.Fatalf("loginUser: parse response: %v", err)
151		}
152		if resp.Data.Token == "" {
153			t.Fatalf("loginUser: got empty token; body: %s", w.Body.String())
154		}
155		return resp.Data.Token
156	}
157	
158	// parseResponse unmarshals the JSON response body into target.
159	// It fails the test if unmarshalling fails.
160	func parseResponse(t *testing.T, w *httptest.ResponseRecorder, target interface{}) {
161		t.Helper()
162		if err := json.Unmarshal(w.Body.Bytes(), target); err != nil {
163			t.Fatalf("parseResponse: %v; body: %s", err, w.Body.String())
164		}
165	}
166	
167	// assertStatus fails the test if the recorder's status code does not match expected.
168	func assertStatus(t *testing.T, w *httptest.ResponseRecorder, expected int) {
169		t.Helper()
170		if w.Code != expected {
171			t.Errorf("expected HTTP %d, got %d; body: %s", expected, w.Code, w.Body.String())
172		}
